if not files_ok:
    st.markdown(
        '<div style="display:flex; flex-direction:column; align-items:center;'
        'justify-content:center; min-height:70vh; padding:20px;">'
        '<p style="font-size:0.85rem; color:#6b7280; margin:0 0 20px 0; text-align:center;">'
