        "puis cliquez sur **Lancer la simulation**."
    )
    st.stop()


#
# SIMULATION
#
if run_btn:
    if mode == "manuel" and not injected:
        st.error("Veuillez sélectionner un vol à perturber dans la barre latérale avant de lancer la simulation.")
        st.stop()

    with st.spinner("Simulation Monte Carlo en cours…"):
        pb = st.progress(0, text="Initialisation…")

        # ── Fixer la graine avant le premier run ─────────────
        # On sauvegarde l'état aléatoire numpy AVANT la simulation
        # principale. Si le tampon est actif, on restaurera cet état
        # identique avant la simulation de référence.
        #
        # Pourquoi c'est nécessaire dans les deux modes :
        #
        #   Mode Auto (N=200) : sans graine fixe, les 200 tirages Gamma
        #     et les états Markov diffèrent entre les deux runs. Le delta
        #     OTP reflète à la fois l'effet du tampon ET le hasard.
        #     Avec la même graine, les deux runs sont identiques sauf
        #     le slack → delta OTP = effet réel du tampon uniquement.
        #
        #   Mode Manuel (N=1) : une seule simulation, le risque est
        #     encore plus grand — un seul état Markov différent peut
        #     inverser le résultat.
        #
        # np.random.seed(42) fixe le point de départ.
        # np.random.get_state() / set_state() permet de rejouer
        # exactement la même séquence de nombres aléatoires.
        np.random.seed(42)
        rng_state = np.random.get_state()   # sauvegarde l'état initial

        df_agg, otp_arr, prop_arr, all_results = run_monte_carlo(
            df_sched, df_crew, mt, gs, gsc, mm, mp,
            n_simulations=n_sims,
            otp_threshold=otp_thresh,
            progress_bar=pb,
            mode=mode,
            use_markov=use_markov,
            injected_delays=injected,
            hub_airport=hub_airport if hub_enabled else None,
            hub_factor=hub_factor,
            slack_config=slack_config,
        )
        pb.empty()

        df_agg_base = otp_arr_base = prop_arr_base = None
        if slack_enabled and slack_config:
            pb2 = st.progress(0, text="Simulation de référence (sans tampon)…")

            # ── Restaurer l'état aléatoire identique ─────────
            # La simulation de référence repart exactement du même
            # point aléatoire que la simulation principale.
            # → Même tirages Gamma, mêmes états Markov, même séquence
            # → Seul le slack_config = None change
            # → Le delta OTP / delta propagation mesure l'effet pur
            #    du tampon, sans bruit aléatoire parasite.
            np.random.set_state(rng_state)

            df_agg_base, otp_arr_base, prop_arr_base, _ = run_monte_carlo(
                df_sched, df_crew, mt, gs, gsc, mm, mp,
                n_simulations=n_sims,
                otp_threshold=otp_thresh,
                progress_bar=pb2,
                mode=mode,
                use_markov=use_markov,
                injected_delays=injected,
                hub_airport=hub_airport if hub_enabled else None,
                hub_factor=hub_factor,
                slack_config=None,
            )
            pb2.empty()

    st.session_state["sim_results"] = dict(
        df_agg        = df_agg,
        otp_arr       = otp_arr,
        prop_arr      = prop_arr,
        all_results   = all_results,
        sim_example   = all_results[int(np.argsort(otp_arr)[len(otp_arr) // 2])],
        n_sims        = n_sims,
        otp_thresh    = otp_thresh,
        injected      = injected,
        mode          = mode,
        use_markov    = use_markov,
        hub_airport   = hub_airport if hub_enabled else None,
        hub_factor    = hub_factor,
        hub_enabled   = hub_enabled,
        slack_enabled = slack_enabled,
        slack_config  = slack_config,
        df_agg_base   = df_agg_base,
        otp_arr_base  = otp_arr_base,
        prop_arr_base = prop_arr_base,
    )

sr            = st.session_state["sim_results"]
df_agg        = sr["df_agg"]
otp_arr       = sr["otp_arr"]
prop_arr      = sr["prop_arr"]
all_results   = sr["all_results"]
sim_example   = sr["sim_example"]
n_sims        = sr["n_sims"]
otp_thresh    = sr["otp_thresh"]
injected      = sr.get("injected", {})
mode          = sr.get("mode", "auto")
hub_airport   = sr.get("hub_airport", None)
hub_factor    = sr.get("hub_factor", 1.2)
hub_enabled   = sr.get("hub_enabled", False)
slack_enabled = sr.get("slack_enabled", False)
slack_config  = sr.get("slack_config", None)
df_agg_base   = sr.get("df_agg_base", None)
otp_arr_base  = sr.get("otp_arr_base", None)
prop_arr_base = sr.get("prop_arr_base", None)
delay_map     = df_agg.set_index("flight_id")["mean_arr_delay"].to_dict()
otp_map       = df_agg.set_index("flight_id")["otp_rate"].to_dict()


#
# BADGES MODE ACTIF
#
badge_row = []
scope_label = ""  # initialisé ici pour éviter NameError dans les sections suivantes

if mode == "manuel" and injected:
    n_inj = len(injected)
    min_inj = list(injected.values())[0]
    fids_list = list(injected.keys())
    markov_label = "Markov actif" if sr.get("use_markov", True) else "Sans Markov (turnaround fixe)"
    if n_inj == 1:
        fid_inj = fids_list[0]
        row_inj = df_sched[df_sched["flight_id"] == fid_inj]
