st.markdown("")
st.divider()


# ══════════════════════════════════════════════════════════════
# SECTION TAMPON VARIABLE — ANALYSE COÛT / BÉNÉFICE
# ══════════════════════════════════════════════════════════════
if slack_enabled and slack_config and df_agg_base is not None:

    s_min        = slack_config["minutes"]
    s_scope      = slack_config.get("scope", "global")
    n_slack_vols = int(df_agg["slack_affected"].sum()) if "slack_affected" in df_agg.columns else 0

    section_header_slack(f"Analyse Tampon Variable — +{s_min} min · {scope_label}")

    otp_base   = float(otp_arr_base.mean())
    otp_slack  = float(otp_arr.mean())
    delta_otp  = otp_slack - otp_base

    prop_base  = float(prop_arr_base.mean())
    prop_slack = float(prop_arr.mean())
    delta_prop = prop_slack - prop_base

    delay_base  = float(df_agg_base["mean_arr_delay"].mean())
    delay_slack = float(df_agg["mean_arr_delay"].mean())
    delta_delay = delay_slack - delay_base

    # ── Coût programme réel ────────────────────────────────────────────────
    # total_slack_min_config : minutes configurées (ce qu'on VOULAIT ajouter)
    # total_slack_absorbed   : minutes effectivement absorbées (slack_applied)
    #
    # Différence possible quand le plancher min_turnaround bloque l'effet :
    #   turn_effectif = max(min_turn, turn_Markov − tampon)
    #   Si turn_Markov = min_turn (état Normal), turn_effectif = min_turn
    #   → slack_applied = 0 → aucun effet sur le programme réel
    #
    # La métrique pertinente pour "coût programme" est total_slack_absorbed.
    total_slack_min_config = n_slack_vols * s_min   # tampon configuré (affiché en référence)
    if "mean_slack_absorbed" in df_agg.columns and "slack_affected" in df_agg.columns:
        total_slack_absorbed = float(
            df_agg.loc[df_agg["slack_affected"] == True, "mean_slack_absorbed"].sum()
        )
    else:
        total_slack_absorbed = float(total_slack_min_config)

    # Plancher bloqué si aucune absorption réelle alors qu'un tampon était demandé
    floor_blocked = (total_slack_min_config > 0) and (total_slack_absorbed < 0.5)

    # total_slack_min utilisé pour l'affichage et l'efficience = absorbé réel
    total_slack_min = total_slack_absorbed

    arrow_otp   = "▲" if delta_otp   >= 0 else "▼"
    arrow_prop  = "▲" if delta_prop  >= 0 else "▼"
    arrow_delay = "▲" if delta_delay >= 0 else "▼"
    css_otp   = "#27ae60" if delta_otp   >= 0 else "#e74c3c"
    css_prop  = "#27ae60" if delta_prop  <= 0 else "#e74c3c"
    css_delay = "#27ae60" if delta_delay <= 0 else "#e74c3c"

    sk1, sk2, sk3, sk4 = st.columns(4)
    sk1.markdown(kpi_card_slack(
        "Gain OTP",
        f'<span style="color:{css_otp}">{arrow_otp} {abs(delta_otp):.1f} pts</span>',
        f"Base : {otp_base:.1f} % → Avec tampon : {otp_slack:.1f} %"
    ), unsafe_allow_html=True)
    sk2.markdown(kpi_card_slack(
        "Variation propagation",
        f'<span style="color:{css_prop}">{arrow_prop} {abs(delta_prop):.2f}×</span>',
        f"Base : {prop_base:.2f}× → Avec tampon : {prop_slack:.2f}×"
    ), unsafe_allow_html=True)
    sk3.markdown(kpi_card_slack(
        "Gain retard moyen",
        f'<span style="color:{css_delay}">{arrow_delay} {abs(delta_delay):.1f} min</span>',
        f"Base : {delay_base:.1f} min → Avec tampon : {delay_slack:.1f} min"
    ), unsafe_allow_html=True)
    sk4.markdown(kpi_card_slack(
        "Coût programme",
        f"{total_slack_absorbed:.0f} min absorbées" if not floor_blocked else "0 min (plancher actif)",
        (f"Configuré : {n_slack_vols} vols × {s_min} min  |  "
         f"⚠️ Plancher min_turnaround a bloqué l'effet")
        if floor_blocked else
        f"{n_slack_vols} vols × {s_min} min configurés → {total_slack_absorbed:.0f} min effectifs"
    ), unsafe_allow_html=True)

    st.markdown("")

    cmp1, cmp2 = st.columns(2)

    with cmp1:
        st.caption("**Distribution OTP** — avec tampon vs sans tampon")
        fig_otp_cmp = go.Figure()
        fig_otp_cmp.add_trace(go.Histogram(
            x=otp_arr_base, nbinsx=25,
            marker=dict(color="#94a3b8", opacity=0.7), name="Sans tampon",
        ))
        fig_otp_cmp.add_trace(go.Histogram(
            x=otp_arr, nbinsx=25,
            marker=dict(color="#0e7490", opacity=0.75), name=f"Avec tampon (+{s_min} min)",
        ))
        fig_otp_cmp.add_vline(x=otp_base,  line_dash="dash", line_color="#94a3b8", line_width=2,
                               annotation_text=f"  Base {otp_base:.1f}%", annotation_font_color="#94a3b8")
        fig_otp_cmp.add_vline(x=otp_slack, line_dash="dash", line_color="#0e7490", line_width=2,
                               annotation_text=f"  Tampon {otp_slack:.1f}%", annotation_font_color="#0e7490")
        fig_otp_cmp.update_layout(
            template="plotly_white", height=300, barmode="overlay",
            xaxis_title="Score OTP (%)", yaxis_title="Nombre de simulations",
            margin=dict(l=10, r=10, t=10, b=40),
            legend=dict(font=dict(size=10), orientation="h", yanchor="top", y=1.12),
            paper_bgcolor="white", plot_bgcolor="#fafafa",
            font=dict(family="Barlow, sans-serif"),
        )
        fig_otp_cmp.update_xaxes(showgrid=True, gridcolor="#eee")
        fig_otp_cmp.update_yaxes(showgrid=True, gridcolor="#eee")
        st.plotly_chart(fig_otp_cmp, use_container_width=True)

    with cmp2:
        st.caption("**Retard moyen par vol** — avec tampon vs sans tampon")
        merged = df_agg[["flight_id", "mean_arr_delay", "slack_affected"]].merge(
            df_agg_base[["flight_id", "mean_arr_delay"]].rename(
                columns={"mean_arr_delay": "mean_arr_delay_base"}),
            on="flight_id"
        )
        max_d = float(max(merged["mean_arr_delay_base"].max(), merged["mean_arr_delay"].max())) + 2
        fig_sc = go.Figure()
        fig_sc.add_trace(go.Scatter(
            x=[0, max_d], y=[0, max_d], mode="lines",
            line=dict(color="#e5e7eb", dash="dash", width=1.5),
            showlegend=False, hoverinfo="none",
        ))
        for affected, label, color in [
            (True,  f"Vols avec tampon (+{s_min} min)", "#0e7490"),
            (False, "Autres vols",                       "#94a3b8"),
        ]:
            sub = merged[merged["slack_affected"] == affected]
            fig_sc.add_trace(go.Scatter(
                x=sub["mean_arr_delay_base"], y=sub["mean_arr_delay"],
                mode="markers", name=label,
                marker=dict(color=color, size=8, opacity=0.8),
                customdata=sub["flight_id"].values,
                hovertemplate="<b>%{customdata}</b><br>Sans tampon : %{x:.1f} min<br>Avec tampon : %{y:.1f} min<extra></extra>",
            ))
        fig_sc.update_layout(
            template="plotly_white", height=300,
            xaxis_title="Retard moyen sans tampon (min)",
            yaxis_title="Retard moyen avec tampon (min)",
            margin=dict(l=10, r=10, t=10, b=40),
            legend=dict(font=dict(size=10), orientation="h", yanchor="top", y=1.12),
            paper_bgcolor="white", plot_bgcolor="#fafafa",
            font=dict(family="Barlow, sans-serif"),
        )
        fig_sc.update_xaxes(showgrid=True, gridcolor="#eee")
        fig_sc.update_yaxes(showgrid=True, gridcolor="#eee")
        st.caption("Points **sous** la diagonale = améliorés par le tampon.")
        st.plotly_chart(fig_sc, use_container_width=True)

    st.caption("**Impact vol par vol** — gain en minutes et en OTP.")
    df_delta = merged.copy()
    df_delta["delta"] = df_delta["mean_arr_delay_base"] - df_delta["mean_arr_delay"]
    df_delta = df_delta.merge(
        df_agg[["flight_id", "origin", "destination", "otp_rate"]], on="flight_id"
    ).merge(
        df_agg_base[["flight_id", "otp_rate"]].rename(columns={"otp_rate": "otp_rate_base"}),
        on="flight_id"
    ).sort_values("delta", ascending=False)
    df_delta["delta_otp"] = df_delta["otp_rate"] - df_delta["otp_rate_base"]
    df_delta = df_delta.rename(columns={
        "flight_id":           "Vol",
        "origin":              "Depart",
        "destination":         "Arrivee",
        "mean_arr_delay_base": "Retard sans tampon (min)",
        "mean_arr_delay":      "Retard avec tampon (min)",
        "delta":               "Gain (min)",
        "otp_rate_base":       "OTP base (%)",
        "otp_rate":            "OTP tampon (%)",
        "delta_otp":           "Delta OTP (pts)",
        "slack_affected":      "Tamponne",
    })

    st.dataframe(
        df_delta[["Vol", "Depart", "Arrivee",
                  "Retard sans tampon (min)", "Retard avec tampon (min)", "Gain (min)",
                  "OTP base (%)", "OTP tampon (%)", "Delta OTP (pts)", "Tamponne"]]
        .style
        .map(color_delay, subset=["Retard sans tampon (min)", "Retard avec tampon (min)"])
        .map(color_gain,  subset=["Gain (min)", "Delta OTP (pts)"])
        .format({
            "Retard sans tampon (min)": "{:.1f}",
            "Retard avec tampon (min)": "{:.1f}",
            "Gain (min)":               "{:.1f}",
            "OTP base (%)":             "{:.1f}",
            "OTP tampon (%)":           "{:.1f}",
            "Delta OTP (pts)":          "{:+.1f}",
        }),
        use_container_width=True,
        hide_index=True,
        height=min(420, 80 + len(df_delta) * 38),
    )

    # ── Efficience : pts OTP gagnés par heure de programme réellement absorbée ──
    # Si plancher bloqué (total_slack_absorbed≈0) → efficience non calculable
    if total_slack_absorbed >= 0.5:
        efficience = abs(delta_otp) / (total_slack_absorbed / 60)
        efficience_str = f"Efficience : {efficience:.2f} pts OTP par heure de programme absorbée."
    else:
        efficience_str = (
            "Efficience : non calculable — le plancher min_turnaround a annulé l'effet du tampon "
            f"(turn_Markov = min_turn sur les vols concernés, absorption réelle = 0 min)."
        )

    verdict_color = "#27ae60" if delta_otp > 0 else "#e74c3c"

    # ── Message principal ──────────────────────────────────────────────────────
    if floor_blocked:
        # Cas particulier : tampon configuré mais plancher bloque tout
        verdict_body = (
            f'Configurer <strong>+{s_min} min</strong> de tampon sur '
            f'<strong>{n_slack_vols} vol(s)</strong> ({scope_label}) '
            f'n\'a <strong style="color:#e67e22">aucun effet réel</strong> dans cette simulation : '
            f'le plancher <em>min_turnaround</em> a bloqué toute absorption '
            f'(turn_Markov = min_turn → turn_effectif inchangé).<br>'
            f'<strong>Coût programme effectif : 0 min</strong> '
            f'(configuré : {total_slack_min_config} min, absorbé : 0 min).<br>'
            f'<span style="font-size:0.8rem; color:#6b7280;">'
            f'→ Pour que ce tampon agisse, il faut que Markov tire un état Alerte ou Bloqué '
            f'(turn_Markov &gt; min_turn). En mode Auto sur N simulations, l\'effet sera visible '
            f'sur les tirages concernés.</span>'
        )
    else:
        verdict_body = (
            f'Ajouter <strong>+{s_min} min</strong> de tampon sur '
            f'<strong>{n_slack_vols} vol(s)</strong> ({scope_label}) '
            f'coûte <strong>{total_slack_absorbed:.0f} min</strong> de programme effectif '
            f'(configuré : {total_slack_min_config} min, absorbé réellement : {total_slack_absorbed:.0f} min) '
            f'et apporte '
            f'<strong style="color:{verdict_color}">{arrow_otp} {abs(delta_otp):.1f} pts d\'OTP</strong> '
            f'et <strong style="color:{css_prop}">{arrow_prop} {abs(delta_prop):.2f}× de propagation</strong>.<br>'
            f'<span style="font-size:0.8rem; color:#6b7280;">{efficience_str}</span>'
        )

    st.markdown(
        f'<div style="background:#f0fdfa; border:1.5px solid #0e7490; border-radius:8px;'
        f' padding:14px 18px; margin-top:8px;">'
        f'<span style="font-family:\'Barlow Condensed\',sans-serif; font-size:0.72rem;'
        f' font-weight:800; color:#0e7490; letter-spacing:2px; text-transform:uppercase;">'
        f'Réponse à la question métier</span><br><br>'
        f'{verdict_body}'
        f'</div>',
        unsafe_allow_html=True,
    )

    st.divider()


# ══════════════════════════════════════════════════════════════
# SECTION HUB CONGESTION — ANALYSE DE L'IMPACT
# ══════════════════════════════════════════════════════════════
if hub_airport:
    section_header_hub(f"Impact de la Congestion Hub — {hub_airport}")

    df_hub_vols   = df_agg[df_agg["hub_affected"] == True]
    df_other_vols = df_agg[df_agg["hub_affected"] == False]

    n_hub       = len(df_hub_vols)
    otp_hub     = float(df_hub_vols["otp_rate"].mean())         if n_hub > 0 else 0.0
    otp_other   = float(df_other_vols["otp_rate"].mean())       if len(df_other_vols) > 0 else 0.0
    delay_hub   = float(df_hub_vols["mean_arr_delay"].mean())   if n_hub > 0 else 0.0
    delay_other = float(df_other_vols["mean_arr_delay"].mean()) if len(df_other_vols) > 0 else 0.0
    p95_hub     = float(df_hub_vols["p95_arr_delay"].mean())    if n_hub > 0 else 0.0
    otp_delta   = otp_hub - otp_other

    hk1, hk2, hk3, hk4 = st.columns(4)
    hk1.markdown(kpi_card_hub(f"Vols au départ de {hub_airport}", str(n_hub), f"Sur {len(df_agg)} vols au total"), unsafe_allow_html=True)
    hk2.markdown(kpi_card_hub("OTP hub vs réseau", f"{otp_hub:.1f} % / {otp_other:.1f} %", f"Écart : {otp_delta:+.1f} pts"), unsafe_allow_html=True)
    hk3.markdown(kpi_card_hub("Retard moy. au départ du hub", f"{delay_hub:.1f} min", f"Réseau hors hub : {delay_other:.1f} min"), unsafe_allow_html=True)
    hk4.markdown(kpi_card_hub("Retard P95 hub", f"{p95_hub:.1f} min", f"Facteur congestion : {hub_factor:.1f}×"), unsafe_allow_html=True)

    st.markdown("")

    if n_hub > 0:
        dest_cols = st.columns([3, 2])

        with dest_cols[0]:
            st.caption(f"**Retard moyen et taux OTP par destination** depuis **{hub_airport}**")
            df_by_dest = (
                df_hub_vols.groupby("destination")
                .agg(mean_delay=("mean_arr_delay","mean"), p95_delay=("p95_arr_delay","mean"),
                     otp_dest=("otp_rate","mean"), n_vols=("flight_id","count"))
                .reset_index().sort_values("mean_delay", ascending=False)
            )
            def dest_bar_color(d):
                if d <= 10: return "#27ae60"
                if d <= 25: return "#f39c12"
                if d <= 60: return "#e67e22"
                return "#e74c3c"
            fig_dest = go.Figure()
            fig_dest.add_trace(go.Bar(
                x=df_by_dest["destination"], y=df_by_dest["mean_delay"],
                marker_color=[dest_bar_color(d) for d in df_by_dest["mean_delay"]],
                text=df_by_dest["mean_delay"].apply(lambda x: f"{x:.0f} min"),
                textposition="outside",
                customdata=np.column_stack([df_by_dest["otp_dest"].round(1), df_by_dest["n_vols"], df_by_dest["p95_delay"].round(1)]),
                hovertemplate="<b>%{x}</b><br>Retard moyen arrivée : <b>%{y:.1f} min</b><br>Retard P95 : %{customdata[2]} min<br>OTP : %{customdata[0]} %<br>Vols concernés : %{customdata[1]}<extra></extra>",
            ))
            fig_dest.update_layout(template="plotly_white", height=320, xaxis_title=f"Destination depuis {hub_airport}", yaxis_title="Retard moyen arrivée (min)", margin=dict(l=10,r=10,t=20,b=60), paper_bgcolor="white", plot_bgcolor="#fafafa", font=dict(family="Barlow, sans-serif"), showlegend=False)
            fig_dest.update_xaxes(showgrid=False, tickangle=-35)
            fig_dest.update_yaxes(showgrid=True, gridcolor="#eee")
            st.plotly_chart(fig_dest, use_container_width=True)

        with dest_cols[1]:
            st.caption(f"**Comparaison OTP** : vols depuis **{hub_airport}** vs reste du réseau")
            df_compare = pd.DataFrame({"Segment":[f"Vols depuis {hub_airport}","Reste du réseau"], "OTP (%)":[otp_hub,otp_other], "Retard moy (min)":[delay_hub,delay_other]})
            fig_cmp = go.Figure()
            fig_cmp.add_trace(go.Bar(x=df_compare["Segment"], y=df_compare["OTP (%)"], marker_color=["#e67e22","#1a6fa0"], text=df_compare["OTP (%)"].apply(lambda x: f"{x:.1f} %"), textposition="outside", hovertemplate="<b>%{x}</b><br>OTP : %{y:.1f} %<extra></extra>"))
            fig_cmp.update_layout(template="plotly_white", height=240, yaxis_title="Taux OTP (%)", yaxis_range=[0,115], margin=dict(l=10,r=10,t=10,b=20), paper_bgcolor="white", plot_bgcolor="#fafafa", font=dict(family="Barlow, sans-serif"), showlegend=False)
            fig_cmp.update_xaxes(showgrid=False); fig_cmp.update_yaxes(showgrid=True, gridcolor="#eee")
            st.plotly_chart(fig_cmp, use_container_width=True)
            fig_cmp2 = go.Figure()
            fig_cmp2.add_trace(go.Bar(x=df_compare["Segment"], y=df_compare["Retard moy (min)"], marker_color=["#e67e22","#1a6fa0"], text=df_compare["Retard moy (min)"].apply(lambda x: f"{x:.1f} min"), textposition="outside", hovertemplate="<b>%{x}</b><br>Retard moy. : %{y:.1f} min<extra></extra>"))
            fig_cmp2.update_layout(template="plotly_white", height=200, yaxis_title="Retard moy. arrivée (min)", margin=dict(l=10,r=10,t=10,b=20), paper_bgcolor="white", plot_bgcolor="#fafafa", font=dict(family="Barlow, sans-serif"), showlegend=False)
            fig_cmp2.update_xaxes(showgrid=False); fig_cmp2.update_yaxes(showgrid=True, gridcolor="#eee")
            st.plotly_chart(fig_cmp2, use_container_width=True)

        st.caption(f"**Détail vol par vol** depuis **{hub_airport}**")
        df_hub_detail = (
            df_hub_vols[["flight_id","destination","scheduled_departure","aircraft_msn","aircraft_type","mean_arr_delay","p95_arr_delay","otp_rate","propagation_idx"]]
            .rename(columns={"flight_id":"Vol","destination":"Destination","scheduled_departure":"Depart prevu","aircraft_msn":"Avion","aircraft_type":"Type","mean_arr_delay":"Retard moy. (min)","p95_arr_delay":"Retard P95 (min)","otp_rate":"OTP (%)","propagation_idx":"Indice propagation"})
            .sort_values("Retard moy. (min)", ascending=False)
        )
        st.dataframe(
            df_hub_detail.style
                .map(color_delay, subset=["Retard moy. (min)"])
                .format({"Retard moy. (min)":"{:.1f}","Retard P95 (min)":"{:.1f}","OTP (%)":"{:.1f}","Indice propagation":"{:.2f}"}),
            use_container_width=True, hide_index=True, height=min(400, 80+len(df_hub_detail)*38),
        )
    else:
        st.info(f"Aucun vol au départ de **{hub_airport}** trouvé dans le programme.")

    st.divider()


# ══════════════════════════════════════════════════════════════
# SECTION SCÉNARIO — PROPAGATION DU VOL INJECTÉ
# ══════════════════════════════════════════════════════════════
if mode == "manuel" and injected:
    fid_inj = list(injected.keys())[0]
    min_inj = list(injected.values())[0]
    section_header(f"Propagation du Retard Injecté — {fid_inj}")

    row_inj = df_sched[df_sched["flight_id"] == fid_inj]
    if not row_inj.empty:
        msn_inj       = row_inj["aircraft_msn"].iloc[0]
        df_rotation   = df_sched[df_sched["aircraft_msn"] == msn_inj].sort_values("dep_min").reset_index(drop=True)
        fids_rotation = df_rotation["flight_id"].tolist()
        sim_result    = all_results[0]
        inj_pos       = fids_rotation.index(fid_inj) if fid_inj in fids_rotation else -1

        rows_prop = []
        for i, row_r in df_rotation.iterrows():
            fid     = row_r["flight_id"]
            sim_row = sim_result[sim_result["flight_id"] == fid]
            if sim_row.empty: continue
            sim_row   = sim_row.iloc[0]
            dep_prevu = row_r["dep_min"]
            dep_reel  = float(sim_row["dep_actual"])
            arr_reelle= float(sim_row["arr_actual"])
            dep_delay = float(sim_row["dep_delay"])
            arr_delay = float(sim_row["arr_delay"])
            rot_idx   = fids_rotation.index(fid) if fid in fids_rotation else i

            if fid == fid_inj:                           role = "Injecte"
            elif dep_delay > 0:                          role = "Propage"
            elif rot_idx < inj_pos or inj_pos == -1:     role = "A l heure"
            else:                                        role = "Absorbe"

            if hub_airport and (row_r["origin"] in hub_airport if isinstance(hub_airport, list) else row_r["origin"] == hub_airport) and dep_delay > 0:
                role = role + f" hub x{hub_factor:.1f}"
            if slack_config and float(sim_row.get("slack_applied", 0)) > 0:
                role = role + f" tampon+{int(sim_row['slack_applied'])}m"

            rows_prop.append({
                "Vol": fid,
                "Route": f"{row_r['origin']} -> {row_r['destination']}",
                "Dep. prevu": mhm(dep_prevu),
                "Depart reel": mhm(dep_reel),
                "Ret. depart (min)": round(dep_delay, 1),
                "Arr. reelle": mhm(arr_reelle),
                "Ret. arrivee (min)": round(arr_delay, 1),
                "Role": role,
            })

        df_prop = pd.DataFrame(rows_prop)
        colors_bar = []
        for _, r in df_prop.iterrows():
            if "Injecte" in r["Role"]:  colors_bar.append("#C8102E")
            elif "Propage" in r["Role"]: colors_bar.append("#e67e22")
            else:                        colors_bar.append("#27ae60")

        fig_prop = go.Figure()
        fig_prop.add_trace(go.Bar(
            x=df_prop["Vol"], y=df_prop["Ret. arrivee (min)"],
            marker_color=colors_bar,
            text=df_prop["Ret. arrivee (min)"].apply(lambda x: f"{x:.0f} min"),
            textposition="outside",
            customdata=df_prop[["Route","Dep. prevu","Depart reel"]].values,
            hovertemplate="<b>%{x}</b>  %{customdata[0]}<br>Depart prevu : %{customdata[1]}<br>Depart reel : %{customdata[2]}<br>Retard arrivee : <b>%{y:.0f} min</b><extra></extra>",
        ))
        fig_prop.update_layout(
            template="plotly_white", height=300,
            xaxis_title="Vols de la rotation", yaxis_title="Retard arrivee (min)",
            margin=dict(l=10,r=10,t=20,b=40), paper_bgcolor="white", plot_bgcolor="#fafafa",
            font=dict(family="Barlow, sans-serif"), showlegend=False,
        )
        fig_prop.update_yaxes(showgrid=True, gridcolor="#eee")

        hub_note   = (f" + congestion {hub_airport} (x{hub_factor:.1f}) active" if hub_airport else "")
        slack_note = (f" + tampon +{slack_config['minutes']} min actif ({scope_label})" if slack_config else "")
        st.caption(f"Rotation {msn_inj} — rouge = injecte, orange = propage, vert = absorbe. Seul {fid_inj} recoit les {min_inj} min.{hub_note}{slack_note}")
        st.plotly_chart(fig_prop, use_container_width=True)

        st.dataframe(
            df_prop.style
                .map(color_delay, subset=["Ret. depart (min)", "Ret. arrivee (min)"])
                .format({"Ret. depart (min)": "{:.1f}", "Ret. arrivee (min)": "{:.1f}"}),
            use_container_width=True, hide_index=True, height=260,
        )

    st.divider()


#
# SECTION 2 — DISTRIBUTIONS
