section_header("Graphe Orienté du Réseau RAM")

if mode == "manuel" and injected:
    fid_inj_graph = list(injected.keys())[0]
    row_inj_graph = df_sched[df_sched["flight_id"] == fid_inj_graph]
    msn_filter    = row_inj_graph["aircraft_msn"].iloc[0] if not row_inj_graph.empty else sorted(df_sched["aircraft_msn"].unique())[0]
    st.caption(f"Rotation **{msn_filter}** — affichée automatiquement car liée au vol injecté **{fid_inj_graph}**.")
else:
    msn_filter = st.selectbox(
        "Rotation de l'avion :",
        sorted(df_sched["aircraft_msn"].unique()),
        key="graph_msn",
        format_func=lambda x: (
            f"{x}  ({df_sched[df_sched['aircraft_msn']==x]['aircraft_type'].iloc[0]})"
            f"  —  {len(df_sched[df_sched['aircraft_msn']==x])} vols"
        ),
    )

df_g    = df_sched[df_sched["aircraft_msn"] == msn_filter].copy()
G_apt   = nx.MultiDiGraph()
airports = sorted(set(df_g["origin"]) | set(df_g["destination"]))
for apt in airports:
    G_apt.add_node(apt,
                   n_dep=int((df_g["origin"]==apt).sum()),
                   n_arr=int((df_g["destination"]==apt).sum()),
                   city=df_g[df_g["origin"]==apt]["origin_city"].iloc[0]
                        if "origin_city" in df_g.columns and (df_g["origin"]==apt).any() else apt)
for _, r in df_g.sort_values("dep_min").iterrows():
    fid = r["flight_id"]
    G_apt.add_edge(r["origin"], r["destination"],
                   fid=fid, n_vols=1, delay=float(delay_map.get(fid,0)),
                   otp=float(otp_map.get(fid,0)),
                   dep=r["scheduled_departure"], arr=r["scheduled_arrival"],
                   dur=int(r["flight_duration_min"]), msn=r["aircraft_msn"], rtype=r["route_type"], agr=False)

def flight_color(delay):
    if delay <= 10: return "#27ae60"
    if delay <= 25: return "#f39c12"
    if delay <= 60: return "#e67e22"
    return "#e74c3c"

n_apt = len(airports); pos_apt = {}; hub_node = "CMN"
if n_apt == 1:
    pos_apt[airports[0]] = (0.0, 0.0)
elif n_apt == 2:
    others = [a for a in airports if a != hub_node]
    pos_apt[hub_node] = (-3.0, 0.0); pos_apt[others[0]] = (3.0, 0.0)
else:
    pos_apt[hub_node] = (0.0, 0.0)
    others = [a for a in airports if a != hub_node]
    for i, apt in enumerate(others):
        angle = math.pi/2 - i*2*math.pi/len(others)
        r = 4.5 if n_apt > 8 else 3.5
        pos_apt[apt] = (r*math.cos(angle), r*math.sin(angle))

slack_flight_ids = set()
if slack_config and all_results:
    sim0 = all_results[0]
    slack_flight_ids = set(sim0[sim0["slack_applied"] > 0]["flight_id"].tolist())

NODE_R = 0.45
pair_total = defaultdict(int)
for u, v, _ in G_apt.edges(data=True): pair_total[(u,v)] += 1
pair_seen = defaultdict(int); traces_g = []

for u, v, edata in G_apt.edges(data=True):
    x0, y0 = pos_apt[u]; x1, y1 = pos_apt[v]
    delay   = edata["delay"]
    color   = flight_color(delay)
    is_inj  = edata["fid"] in injected
    is_hub  = bool(hub_airport and (u in hub_airport if isinstance(hub_airport, list) else u == hub_airport))
    is_slack= edata["fid"] in slack_flight_ids
    width   = max(1.5, min(5.0, 1.5+delay/20))
    idx_uv  = pair_seen[(u,v)]; pair_seen[(u,v)] += 1
    n_same  = pair_total[(u,v)]; has_rev = pair_total[(v,u)] > 0
    dx=x1-x0; dy=y1-y0; L=math.sqrt(dx**2+dy**2) or 1.0; px=-dy/L; py=dx/L
    if n_same > 1: base = 0.7 if has_rev else 0.0; offset = base+(idx_uv-(n_same-1)/2.0)*0.6
    elif has_rev:  offset = 0.9
    else:          offset = 0.0
    cx=(x0+x1)/2+px*offset; cy=(y0+y1)/2+py*offset
    t_start, t_end = 0.0, 1.0
    for ti in np.linspace(0.0,1.0,200):
        ptx=(1-ti)**2*x0+2*(1-ti)*ti*cx+ti**2*x1; pty=(1-ti)**2*y0+2*(1-ti)*ti*cy+ti**2*y1
        if math.sqrt((ptx-x0)**2+(pty-y0)**2)>=NODE_R: t_start=ti; break
    for ti in np.linspace(1.0,0.0,200):
        ptx=(1-ti)**2*x0+2*(1-ti)*ti*cx+ti**2*x1; pty=(1-ti)**2*y0+2*(1-ti)*ti*cy+ti**2*y1
        if math.sqrt((ptx-x1)**2+(pty-y1)**2)>=NODE_R: t_end=ti; break
    t_trim=np.linspace(t_start,t_end,50)
    bxt=(1-t_trim)**2*x0+2*(1-t_trim)*t_trim*cx+t_trim**2*x1
    byt=(1-t_trim)**2*y0+2*(1-t_trim)*t_trim*cy+t_trim**2*y1
    if is_inj:    line_color="#C8102E"; edge_width=width+2
    elif is_hub:  line_color="#e67e22"; edge_width=width+1
    elif is_slack:line_color="#0e7490"; edge_width=width+1
    else:         line_color=color;     edge_width=width
    traces_g.append(go.Scatter(x=list(bxt)+[None], y=list(byt)+[None], mode="lines", line=dict(color=line_color,width=edge_width), hoverinfo="none", showlegend=False))
    dx_end=float(bxt[-1]-bxt[-4]) if len(bxt)>=4 else (x1-x0); dy_end=float(byt[-1]-byt[-4]) if len(byt)>=4 else (y1-y0)
    traces_g.append(go.Scatter(x=[float(bxt[-1])], y=[float(byt[-1])], mode="markers", marker=dict(size=15,color=line_color,symbol="arrow",angle=90-math.degrees(math.atan2(dy_end,dx_end)),line=dict(width=0)), hoverinfo="none", showlegend=False))
    t_mid=0.5; lx=(1-t_mid)**2*x0+2*(1-t_mid)*t_mid*cx+t_mid**2*x1; ly=(1-t_mid)**2*y0+2*(1-t_mid)*t_mid*cy+t_mid**2*y1
    sign=1 if offset>=0 else -1
    label_prefix = "!" if is_inj else ("H" if is_hub else ("T" if is_slack else ""))
    traces_g.append(go.Scatter(x=[lx+px*0.35*sign], y=[ly+py*0.35*sign], mode="text",
                               text=[f"<b>{label_prefix}{edata['fid']}</b>"],
                               textfont=dict(size=9,color=line_color,family="Barlow, Arial"), hoverinfo="none", showlegend=False))
    hub_note_hover   = (f"<br>Hub congestionne ({hub_airport} x{hub_factor:.1f})" if is_hub else "")
    slack_note_hover = (f"<br>Tampon +{slack_config['minutes']} min applique" if is_slack else "")
    hover_txt = (f"<b>{edata['fid']}</b><br>Route : <b>{u} -> {v}</b><br>Avion : {edata['msn']}<br>Type : {edata['rtype']}<br>Depart : {edata['dep']}  |  Arrivee : {edata['arr']}<br>Duree : {edata['dur']} min<br>Retard moyen : <b>{delay:.0f} min</b><br>OTP : {edata['otp']:.1f} %{hub_note_hover}{slack_note_hover}<extra></extra>")
    traces_g.append(go.Scatter(x=[lx], y=[ly], mode="markers", marker=dict(size=16,color=line_color,opacity=0.0), hovertemplate=hover_txt, showlegend=False))

for apt in G_apt.nodes():
    nd=G_apt.nodes[apt]; x,y=pos_apt[apt]
    is_h=apt==hub_node; is_congested_hub=bool(hub_airport and (apt in hub_airport if isinstance(hub_airport, list) else apt == hub_airport))
    n_total=nd["n_dep"]+nd["n_arr"]
    node_col=("#e67e22" if is_congested_hub else ("#C8102E" if is_h else "#1a2e45"))
    node_sz=54 if is_h else max(40,min(56,30+n_total*2))
    border_col="#ff9900" if is_congested_hub else "white"; border_w=5 if is_congested_hub else 3
    vols_dep=df_g[df_g["origin"]==apt]["flight_id"].tolist()
    avg_d=float(np.mean([delay_map.get(f,0) for f in vols_dep])) if vols_dep else 0.0
    cong_note=(f"<br>Hub congestionne (x{hub_factor:.1f})" if is_congested_hub else "")
    traces_g.append(go.Scatter(x=[x], y=[y], mode="markers",
                               marker=dict(size=node_sz,color=node_col,line=dict(width=border_w,color=border_col),symbol="circle"),
                               hovertemplate=(f"<b>{apt}</b><br>Vols au depart : {nd['n_dep']}<br>Vols a l arrivee : {nd['n_arr']}<br>Retard moyen au depart : {avg_d:.0f} min{cong_note}<extra></extra>"),
                               showlegend=False))
    traces_g.append(go.Scatter(x=[x], y=[y], mode="text", text=[apt],
                               textfont=dict(size=13 if is_h else 11,color="white",family="Barlow Condensed, Arial Black"),
                               hoverinfo="none", showlegend=False))

all_xy_g=list(pos_apt.values()); pad_g=1.8
fig_g=go.Figure(data=traces_g)
hub_subtitle   = (f"  |  Hub : {hub_airport} (x{hub_factor:.1f})" if hub_airport else "")
slack_subtitle = (f"  |  Tampon +{slack_config['minutes']} min ({scope_label})" if slack_config else "")
fig_g.update_layout(
    template="plotly_white", height=580, margin=dict(l=30,r=30,t=55,b=30),
    title=dict(text=(f"<b>Réseau RAM — Rotation {msn_filter}</b>  |  {len(airports)} aéroports  |  {G_apt.number_of_edges()} routes  |  {len(df_g)} vols{hub_subtitle}{slack_subtitle}"),
               font=dict(size=13,family="Barlow, sans-serif")),
    xaxis=dict(showgrid=False,zeroline=False,showticklabels=False,range=[min(v[0] for v in all_xy_g)-pad_g,max(v[0] for v in all_xy_g)+pad_g]),
    yaxis=dict(showgrid=False,zeroline=False,showticklabels=False,range=[min(v[1] for v in all_xy_g)-pad_g,max(v[1] for v in all_xy_g)+pad_g],scaleanchor="x",scaleratio=1),
    paper_bgcolor="white", plot_bgcolor="#f8f9fb", font=dict(family="Barlow, sans-serif"),
)
st.plotly_chart(fig_g, use_container_width=True)

lc1, lc2, lc3, lc4, lc5, lc6 = st.columns(6)
lc1.markdown('<span class="legend-dot" style="background:#27ae60"></span>Retard ≤ 10 min', unsafe_allow_html=True)
lc2.markdown('<span class="legend-dot" style="background:#f39c12"></span>Retard 10–25 min', unsafe_allow_html=True)
lc3.markdown('<span class="legend-dot" style="background:#e67e22"></span>Retard 25–60 min', unsafe_allow_html=True)
lc4.markdown('<span class="legend-dot" style="background:#e74c3c"></span>Retard > 60 min', unsafe_allow_html=True)
if hub_airport:
    lc5.markdown('<span class="legend-dot" style="background:#e67e22;border:2px solid #ff9900"></span>Hub congestionné', unsafe_allow_html=True)
if slack_config:
    lc6.markdown('<span class="legend-dot" style="background:#0e7490"></span>Tampon actif', unsafe_allow_html=True)


#
# TABLEAU — RETARDS ET RECOMMANDATIONS
#
st.markdown("")
section_header("Vols — Retards et Recommandations")

G_imp = nx.DiGraph()
for _, r in df_sched.iterrows():
    G_imp.add_node(r["flight_id"], delay=float(delay_map.get(r["flight_id"],0)))
for msn_x, grp in df_sched.sort_values("dep_min").groupby("aircraft_msn"):
    fids_x = grp["flight_id"].tolist()
    for i in range(len(fids_x)-1): G_imp.add_edge(fids_x[i], fids_x[i+1])
impacts_all = {}
for node in G_imp.nodes():
    succ = list(nx.descendants(G_imp, node))
    casc = float(np.mean([G_imp.nodes[s]["delay"] for s in succ])) if succ else 0.0
    impacts_all[node] = G_imp.nodes[node]["delay"] + 0.4*casc
p90_all = float(np.percentile(list(impacts_all.values()), 90))

# Précalcul des percentiles pour toutes les recommandations (mode Auto)
p80_map = df_agg.set_index("flight_id")["p80_dep_delay"].to_dict()
p90_map = df_agg.set_index("flight_id")["p90_dep_delay"].to_dict()

# ── Précalcul du retard propagé par vol (mode Manuel) ─────────
# En mode Manuel, on connaît exactement le retard propagé reçu
# par chaque vol depuis la simulation (n=1, déterministe).
# On peut donc calculer précisément :
#   tampon_min_otp  : slack qui fait passer le vol SOUS le seuil OTP
#   tampon_absorb   : slack qui absorbe TOUT le retard propagé
# Ces valeurs sont calculées à partir du retard propagé réel de
# la simulation, pas d'une heuristique.
prop_delay_map = {}   # retard propagé reçu par chaque vol
if mode == "manuel" and all_results:
    sim0 = all_results[0]
    for _, row_s in sim0.iterrows():
        fid_s      = row_s["flight_id"]
        dep_delay  = float(row_s["dep_delay"])
        init_delay = float(row_s["initial_delay"])
        # Retard propagé = retard total - retard initial propre
        prop_delay_map[fid_s] = max(0.0, dep_delay - init_delay)

table_rows = []
for _, r in df_g.sort_values("dep_min").iterrows():
    fid    = r["flight_id"]
    delay  = float(delay_map.get(fid, 0))
    otp_v  = float(otp_map.get(fid, 0))
    impact = impacts_all.get(fid, delay)
    is_hub_flight   = bool(hub_airport and (r["origin"] in hub_airport if isinstance(hub_airport, list) else r["origin"] == hub_airport))
    is_slack_flight = fid in slack_flight_ids

    if mode == "manuel":
        # ── Recommandation Mode Manuel ─────────────────────────
        # Basée sur le retard propagé réel reçu par ce vol.
        #
        # Formule :
        #   retard_propage = ce que l'avion précédent transmet à ce vol
        #   tampon_otp     = retard total - seuil_otp + 1
        #                  → slack minimum pour passer sous le seuil OTP
        #   tampon_absorb  = retard_propage
        #                  → slack qui absorbe toute la propagation
        #
        # Exemple AT514 : retard_propage = 30 min, seuil = 15 min
        #   dep_delay = 30 min → tampon_otp = 30 - 15 + 1 = 16 min
        #   → avec +16 min de slack, AT514 passe à 14 min (sous seuil) ✅
        #   tampon_absorb = 30 min → absorbe tout ✅
        prop_recv = prop_delay_map.get(fid, 0.0)
        dep_delay_vol = float(delay_map.get(fid, 0))

        if prop_recv <= 0:
            # Pas de propagation reçue → tampon inutile sur ce vol
            reco = "Aucun retard propagé reçu"
            reco_min = 0
            reco_abs = 0
        else:
            # Tampon pour passer sous le seuil OTP
            tampon_otp = max(0, int(dep_delay_vol - otp_thresh) + 1)
            # Tampon pour absorber tout le retard propagé
            tampon_abs = int(np.ceil(prop_recv))
            reco_min = tampon_otp
            reco_abs = tampon_abs
            if tampon_otp <= 0:
                reco = f"Deja sous seuil OTP"
            else:
                reco = f"OTP : +{tampon_otp} min  |  Absorb. totale : +{tampon_abs} min"

        table_rows.append({
            "Vol":                  fid,
            "Route":                f"{r['origin']} -> {r['destination']}",
            "Avion":                r["aircraft_msn"],
            "Depart":               r["scheduled_departure"],
            "Arrivee":              r["scheduled_arrival"],
            "Ret. propagé (min)":   round(prop_recv, 1),
            "Ret. total (min)":     round(dep_delay_vol, 1),
            "OTP (%)":              round(otp_v, 1),
            "Tampon OTP (min)":     reco_min,
            "Tampon absorb. (min)": reco_abs,
            "Recommandation":       reco,
            "Priorite":             ("Critique" if impact>=p90_all else "Haute" if delay>=45 else "Normale"),
            "Hub":                  ("Hub" if is_hub_flight else ""),
            "Tampon":               ("T"   if is_slack_flight else ""),
        })

    else:
        # ── Recommandation Mode Auto ────────────────────────────
        # P80 = tampon qui absorbe 8 retards sur 10 → usage quotidien
        # P90 = tampon qui absorbe 9 retards sur 10 → vols critiques
        p80 = max(5, int(p80_map.get(fid, 0)))
        p90 = max(5, int(p90_map.get(fid, 0)))

        table_rows.append({
            "Vol":               fid,
            "Route":             f"{r['origin']} -> {r['destination']}",
            "Avion":             r["aircraft_msn"],
            "Depart":            r["scheduled_departure"],
            "Arrivee":           r["scheduled_arrival"],
            "Retard moy. (min)": round(delay, 1),
            "Impact cascade":    round(impact, 1),
            "OTP (%)":           round(otp_v, 1),
            "P80 (min)":         p80,
            "P90 (min)":         p90,
            "Recommandation":    f"Courant : +{p80} min  |  Securise : +{p90} min",
            "Priorite":          ("Critique" if impact>=p90_all else "Haute" if delay>=45 else "Normale"),
            "Hub":               ("Hub"    if is_hub_flight   else ""),
            "Tampon":            ("T"      if is_slack_flight else ""),
        })

df_table = pd.DataFrame(table_rows)

if mode == "manuel":
    # ── Mode Manuel : recommandation basée sur le retard propagé réel ─
    # "Tampon OTP"    = slack minimum pour passer sous le seuil OTP
    # "Tampon absorb" = slack qui absorbe toute la propagation (retard=0)
    # Ces valeurs sont calculées depuis la simulation déterministe,
    # pas depuis une heuristique statistique.
    st.caption(
        f"**Tampon OTP** : slack minimum pour passer sous le seuil {otp_thresh} min.  "
        "**Tampon absorb.** : slack pour absorber tout le retard propagé reçu."
    )
    cols_table = ["Vol","Route","Avion","Depart","Arrivee",
                  "Ret. propagé (min)","Ret. total (min)","OTP (%)",
                  "Tampon OTP (min)","Tampon absorb. (min)",
                  "Recommandation","Priorite","Hub","Tampon"]
    fmt_table  = {
        "Ret. propagé (min)":   "{:.1f}",
        "Ret. total (min)":     "{:.1f}",
        "OTP (%)":              "{:.1f}",
        "Tampon OTP (min)":     "{:.0f}",
        "Tampon absorb. (min)": "{:.0f}",
    }
else:
    st.caption(
        "**P80** : tampon qui absorbe 8 retards sur 10 (usage quotidien).  "
        "**P90** : tampon qui absorbe 9 retards sur 10 (vols critiques / connexions)."
    )
    cols_table = ["Vol","Route","Avion","Depart","Arrivee",
                  "Retard moy. (min)","Impact cascade","OTP (%)","P80 (min)","P90 (min)",
                  "Recommandation","Priorite","Hub","Tampon"]
    fmt_table  = {
        "Retard moy. (min)": "{:.1f}",
        "Impact cascade":    "{:.1f}",
        "OTP (%)":           "{:.1f}",
        "P80 (min)":         "{:.0f}",
        "P90 (min)":         "{:.0f}",
    }

cols_table = [c for c in cols_table if c in df_table.columns]
if mode == "manuel":
    delay_subset = [c for c in ["Ret. propagé (min)", "Ret. total (min)"] if c in cols_table]
else:
    delay_subset = [c for c in ["Retard moy. (min)", "P80 (min)", "P90 (min)"] if c in cols_table]

# Couleur pour les colonnes de tampon recommandé
def color_tampon_reco(val):
    try:
        v = float(val)
        if v <= 0:  return "color:#27ae60; font-weight:600"
        if v <= 15: return "color:#e67e22; font-weight:600"
        return "color:#e74c3c; font-weight:600"
    except:
        return ""

style_table = df_table[cols_table].style.map(color_delay, subset=delay_subset).format(fmt_table)
if mode == "manuel":
    tampon_cols = [c for c in ["Tampon OTP (min)", "Tampon absorb. (min)"] if c in cols_table]
    if tampon_cols:
        style_table = style_table.map(color_tampon_reco, subset=tampon_cols)

st.dataframe(style_table, use_container_width=True, hide_index=True, height=320)
st.divider()


#
# SECTION 4 — DIAGNOSTIC DÉTAILLÉ
#
section_header("Diagnostic Détaillé — Simulation Représentative")

if mode == "manuel":
    extra_hub   = (f" — congestion {hub_airport} (x{hub_factor:.1f}) active" if hub_airport else "")
    extra_slack = (f" — tampon +{slack_config['minutes']} min actif sur {scope_label}" if slack_config else "")
    st.caption("Résultats de la simulation avec retard injecté. Chaque retard propagé vient uniquement de la contrainte avion ou équipage — aucun bruit Gamma." + extra_hub + extra_slack)
else:
    extra_hub   = (f" — congestion {hub_airport} (x{hub_factor:.1f}) active" if hub_airport else "")
    extra_slack = (f" — tampon +{slack_config['minutes']} min actif sur {scope_label}" if slack_config else "")
    st.caption("Résultats d'une simulation OTP médian. Chaque retard est décomposé entre sa part initiale (loi Gamma) et sa part propagée." + extra_hub + extra_slack)

etat_labels = {0: "Normal", 1: "Alerte", 2: "Bloque"}
rows_diag   = []
for _, row in sim_example.sort_values(["aircraft_msn", "dep_min"]).iterrows():
    # ── Retard propagé = retard total - retard initial ────────
    # Formule : Ret_propage = Ret_depart_total - Ret_initial
    #   Ret_initial  = retard propre du vol (Gamma en auto, injecté en manuel)
    #   Ret_propage  = retard hérité de l'avion ou équipage précédent
    #   Ret_total    = Ret_initial + Ret_propage
    prop = row["dep_delay"] - row["initial_delay"]

    # ── Indice de propagation de ce vol ──────────────────────
    # Formule : Indice = Ret_arrivee / Ret_initial  (si Ret_initial >= 1 min)
    # Interprétation :
    #   1.0 → le retard final = le retard initial (pas d'amplification)
    #   2.0 → le retard a doublé en cours de route (forte propagation)
    #   0.5 → le retard a été absorbé à moitié
    #   —   → vol sans retard initial propre (division impossible, valeur absurde)
    #
    # GARDE : si Ret_initial < 1 min, le vol est purement propagé
    # (il n'a pas généré de retard lui-même).  Diviser arr_delay / 0.1
    # produirait des valeurs aberrantes comme 670× ou 620×.
    # On affiche "—" pour indiquer que l'indice n'est pas applicable.
    ini_val = float(row["initial_delay"])
    if ini_val >= 1.0:
        prop_idx = round(float(row["arr_delay"]) / ini_val, 2)
    else:
        prop_idx = None   # affiché "—" dans le tableau

    # ── Statut OTP ────────────────────────────────────────────
    # Basé sur : dep_delay <= otp_threshold (seuil choisi en sidebar)
    otp_statut = "A l heure" if row["on_time"] else "En retard"

    r_diag = {
        "Avion":              row["aircraft_msn"],
        "Vol":                row["flight_id"],
        "Route":              f"{row['origin']} -> {row['destination']}",
        "Dep. prevu":         mhm(row["dep_min"]),
        "Dep. reel":          mhm(row["dep_actual"]),
        "Ret. propage (min)": round(float(max(0, prop)), 1),
        "Ret. depart total":  round(float(row["dep_delay"]), 1),
        "Arr. prevue":        mhm(row["arr_min"]),
        "Arr. reelle":        mhm(row["arr_actual"]),
        "Ret. arrivee (min)": round(float(row["arr_delay"]), 1),
        "Indice propagation": prop_idx,
        # ── Turnaround effectif (après tampon + plancher min_turn) ───────
        # On affiche turnaround_effectif (valeur réellement utilisée dans
        # le calcul avion_pret), pas turnaround_actual (valeur brute Markov).
        # La colonne "Tampon applique" indique séparément les minutes absorbées.
        "Turnaround (min)":   round(float(row.get("turnaround_effectif",
                                                   row["turnaround_actual"])), 1),
        "Etat Markov":        etat_labels.get(int(row["markov_state"]), "?"),
        # ── OTP : colonne séparée, claire ─────────────────────
        "OTP":                otp_statut,
        # ── Tampon : colonne séparée (oui/non + minutes) ──────
        # Indique si le turnaround de ce vol a bénéficié d'un tampon.
        # N'a RIEN à voir avec le statut OTP — les deux sont indépendants.
        "Tampon applique":    (f"+{int(row['slack_applied'])} min"
                               if float(row.get("slack_applied", 0)) > 0
                               else "Non"),
        # ── Hub : colonne séparée ─────────────────────────────
        "Hub":                ("Oui" if hub_airport and (row["origin"] in hub_airport if isinstance(hub_airport, list) else row["origin"] == hub_airport)
                               else "Non"),
    }
    if mode == "auto":
        r_diag["Ret. Gamma (min)"] = round(float(row["initial_delay"]), 1)
    rows_diag.append(r_diag)

df_diag = pd.DataFrame(rows_diag)

if mode == "auto":
    cols_diag = ["Avion","Vol","Route","Dep. prevu","Dep. reel",
                 "Ret. Gamma (min)","Ret. propage (min)","Ret. depart total",
                 "Arr. prevue","Arr. reelle","Ret. arrivee (min)",
                 "Indice propagation","Turnaround (min)","Etat Markov",
                 "OTP","Tampon applique","Hub"]
else:
    cols_diag = ["Avion","Vol","Route","Dep. prevu","Dep. reel",
                 "Ret. propage (min)","Ret. depart total",
                 "Arr. prevue","Arr. reelle","Ret. arrivee (min)",
                 "Indice propagation","Turnaround (min)","Etat Markov",
                 "OTP","Tampon applique","Hub"]

# Ne garder que les colonnes pertinentes
if not hub_airport:
    cols_diag = [c for c in cols_diag if c != "Hub"]
if not slack_config:
    cols_diag = [c for c in cols_diag if c != "Tampon applique"]

df_diag = df_diag[[c for c in cols_diag if c in df_diag.columns]]

if mode == "auto":
    cd1, cd2 = st.columns([2, 1])
    with cd1:
        avion_f = st.selectbox("Filtrer par avion :",
                               ["Tous"] + sorted(df_diag["Avion"].unique().tolist()),
                               key="diag_filter")
    with cd2:
        st.caption(
            "**Ret. depart total = Ret. Gamma + Ret. propage**  |  "
            "**Indice propagation = Ret. arrivee / Ret. initial**  (— si aucun retard initial propre)  |  "
            "**Turnaround = valeur effectivement utilisée** (après tampon + plancher)  |  "
            "Vert ≤ 15 min  |  Rouge > 15 min"
        )
    if avion_f != "Tous":
        df_diag = df_diag[df_diag["Avion"] == avion_f]
else:
    fid_diag = list(injected.keys())[0]
    msn_diag = df_sched[df_sched["flight_id"] == fid_diag]["aircraft_msn"].iloc[0]
    fids_rot = df_sched[df_sched["aircraft_msn"] == msn_diag]["flight_id"].tolist()
    df_diag  = df_diag[df_diag["Vol"].isin(fids_rot)]
    st.caption(
        f"Rotation {msn_diag}  |  "
        "**Ret. depart total = Ret. propage** (retard injecté exclu)  |  "
        "**Indice propagation = Ret. arrivee / Ret. initial**  (— si aucun retard initial propre)  |  "
        "**Turnaround = valeur effectivement utilisée** (après tampon + plancher)  |  "
        "Vert ≤ 15 min  |  Rouge > 15 min"
    )

# Colonne OTP : couleur verte/rouge
def color_otp(val):
    if val == "A l heure": return "color:#27ae60; font-weight:700"
    if val == "En retard":  return "color:#e74c3c; font-weight:700"
    return ""

# Colonne Tampon : teal si actif
def color_tampon(val):
    if val != "Non": return "color:#0e7490; font-weight:700"
    return "color:#9aa3b2"

# Indice de propagation : vert si < 1, orange si 1-2, rouge si > 2
def color_prop_idx(val):
    try:
        v = float(val)
        if v <= 1.0: return "color:#27ae60; font-weight:600"
        if v <= 2.0: return "color:#e67e22; font-weight:600"
        return "color:#e74c3c; font-weight:700"
    except:
        return ""

cols_present = df_diag.columns.tolist()
delay_cols   = [c for c in ["Ret. Gamma (min)","Ret. propage (min)",
                             "Ret. depart total","Ret. arrivee (min)"]
                if c in cols_present]
fmt_diag = {c: "{:.1f}" for c in delay_cols}
# Turnaround : numérique (effectif), format standard
fmt_diag["Turnaround (min)"] = "{:.1f}"
# Indice propagation : format numérique standard, traiter None après
if "Indice propagation" in cols_present:
    fmt_diag["Indice propagation"] = "{:.2f}"
fmt_diag = {k: v for k, v in fmt_diag.items() if k in cols_present}

style = (df_diag.style
    .map(color_delay,  subset=delay_cols)
    .map(color_markov, subset=["Etat Markov"])
    .map(color_otp,    subset=["OTP"])
    .map(color_prop_idx, subset=["Indice propagation"])
    .format(fmt_diag)
)
if "Tampon applique" in cols_present:
    style = style.map(color_tampon, subset=["Tampon applique"])

st.dataframe(
    style,
    use_container_width=True, height=460,
)
st.divider()


