#
# SECTION OPTIMISEUR — SUBSTITUTION D'AVION
#
if "sim_results" in st.session_state:

    def _mhm_opt(m):
        m = int(m) % 1440
        return f"{m//60:02d}:{m%60:02d}"

    def _kpi_opt(label, value, delta=""):
        delta_html = f'<div class="kpi-delta">{delta}</div>' if delta else ""
        return f"""<div class="kpi-card-opt">
            <div class="kpi-value">{value}</div>
            <div class="kpi-label">{label}</div>
            {delta_html}</div>"""

    def _color_statut_opt(val):
        if "✅" in str(val): return "color:#16a34a; font-weight:700"
        if "⚠️" in str(val): return "color:#d97706; font-weight:700"
        if "❌" in str(val): return "color:#dc2626; font-weight:700"
        return ""

    def _color_gain_opt(val):
        try:
            v = float(val)
            if v > 20: return "color:#16a34a; font-weight:700"
            if v > 5:  return "color:#2dd4bf; font-weight:600"
            return "color:#6b7280"
        except: return ""

    st.markdown('<div class="section-header-opt"> Optimiseur — Substitution d\'Avion</div>',
                unsafe_allow_html=True)

    # ── Activation du scénario ─────────────────────────────
    _enable_col, _info_col = st.columns([1, 3])
    with _enable_col:
        enable_optimizer = st.checkbox(
            " Activer l'optimiseur",
            value=False,
            help="Cochez pour activer l'analyse de substitution d'avion",
            key="enable_optimizer_checkbox"
        )

    with _info_col:
        if enable_optimizer:
            st.success("✅ Mode optimiseur **ACTIVÉ** — Analysez les vols retardés")
        else:
            st.info("ℹ️ Mode optimiseur **DÉSACTIVÉ** — Activez pour analyser les substitutions")

    # Exécuter l'optimiseur seulement s'il est activé
    if enable_optimizer:
        # ── Paramètres ────────────────────────────────────────
        with st.expander("⚙️ Paramètres de l'optimiseur", expanded=True):
            _p1, _p2, _p3 = st.columns([1.5, 1.5, 1])

            with _p1:
                delay_threshold_opt = st.slider(
                    " Seuil de déclenchement (min)",
                    min_value=10,
                    max_value=120,
                    value=30,
                    step=5,
                    help="Ne traiter que les vols avec retard moyen arrivée ≥ ce seuil",
                )

            with _p2:
                st.metric(
                    "Vols analysables",
                    int((df_agg["mean_arr_delay"] >= delay_threshold_opt).sum()),
                    help="Nombre de vols avec retard ≥ seuil"
                )

            with _p3:
                show_infeasible_opt = st.checkbox(
                    " Afficher infaisables",
                    value=False,
                    help="Montrer aussi les swaps impossible (pour comprendre pourquoi)",
                )

        # ── Bouton de lancement ────────────────────────────────
        st.markdown("")
        _launch_col, _clear_col, _spacer = st.columns([1, 1, 2])

        with _launch_col:
            launch_analysis = st.button(
                " Lancer l'analyse de substitution",
                key="launch_optimizer_button",
                use_container_width=True,
                type="primary",
                help="Analyser les avions retardés et trouver les meilleures substitutions"
            )

        with _clear_col:
            if st.button(" Réinitialiser", key="reset_optimizer_button", use_container_width=True):
                if "optimizer_results" in st.session_state:
                    del st.session_state.optimizer_results
                st.rerun()

        # ── Exécuter l'analyse si le bouton est cliqué ──────────
        if launch_analysis:
            n_delayed_opt = int((df_agg["mean_arr_delay"] >= delay_threshold_opt).sum())

            if n_delayed_opt == 0:
                st.warning(f"⚠️ Aucun vol ne dépasse {delay_threshold_opt} min de retard moyen. "
                          f"Réduisez le seuil pour analyser plus de vols.")
            else:
                with st.spinner(f" Analyse de {n_delayed_opt} vol(s) en retard… (cela peut prendre quelques secondes)"):
                    df_opt, swap_list_opt = run_swap_optimizer(
                        df_agg=df_agg, all_results=all_results,
                        df_sched=df_sched, df_crew=df_crew,
                        min_turnaround=mt, otp_threshold=otp_thresh,
                        delay_threshold=delay_threshold_opt,
                    )

                    # Sauvegarder les résultats dans la session
                    st.session_state.optimizer_results = {
                        "df_opt": df_opt,
                        "swap_list_opt": swap_list_opt,
                        "delay_threshold_opt": delay_threshold_opt,
                        "show_infeasible_opt": show_infeasible_opt,
                        "n_delayed_opt": n_delayed_opt,
                    }

                st.success("✅ Analyse terminée!")
                st.rerun()

        # ── Afficher les résultats s'ils existent ──────────────
        if "optimizer_results" in st.session_state:
            res = st.session_state.optimizer_results
            df_opt = res["df_opt"]
            swap_list_opt = res["swap_list_opt"]
            show_infeasible_opt = res.get("show_infeasible_opt", False)

            if not df_opt.empty:
                # ── KPI globaux ──────────────────────────────
                st.markdown("###  Résumé de l'Analyse")
                st.divider()

                _n_tot  = len(swap_list_opt)
                _n_ok   = sum(1 for s in swap_list_opt if s.has_solution)
                _n_otp  = sum(1 for s in swap_list_opt
                              if s.has_solution and s.best.new_delay <= otp_thresh)
                _gain   = sum(s.best.delay_saved for s in swap_list_opt if s.has_solution)
                _rate   = _n_ok / _n_tot * 100 if _n_tot else 0

                _ok1, _ok2, _ok3, _ok4 = st.columns(4)
                with _ok1:
                    st.metric(
                        " Vols Analysés",
                        _n_tot,
                        f"Retard ≥ {res['delay_threshold_opt']} min",
                        delta_color="off"
                    )
                with _ok2:
                    st.metric(
                        "✅ Substitutions Faisables",
                        f"{_n_ok}/{_n_tot}",
                        f"{_rate:.0f}% de couverture"
                    )
                with _ok3:
                    st.metric(
                        " OTP Restauré",
                        f"{_n_otp}",
                        f"< {otp_thresh} min après swap"
                    )
                with _ok4:
                    st.metric(
                        "⏱️ Gain Total",
                        f"{_gain:.0f} min",
                        f"Moy. {_gain/_n_ok:.0f} min/vol" if _n_ok else "—"
                    )

                st.markdown("")
                st.divider()

                # ── Onglets de visualisation ──────────────────────────────
                _t1, _t2, _t3, _t4 = st.tabs([
                    " Tableau Récapitulatif",
                    " Fiche Détaillée par Vol",
                    " Graphiques d'Analyse",
                    " Résumé d'Exécution",
                ])

            # ── Onglet 1 : Tableau ────────────────────────
            with _t1:
                st.markdown("####  Tableau Récapitulatif des Substitutions Possibles")

                # Filtres
                _f1, _f2, _f3 = st.columns([1, 1, 1])
                with _f1:
                    filter_faisable = st.checkbox(
                        "✅ Montrer seulement les faisables",
                        value=True,
                        help="Afficher uniquement les vols avec substitution faisable"
                    )
                with _f2:
                    filter_otp = st.checkbox(
                        " Montrer seulement OTP restauré",
                        value=False,
                        help="Afficher uniquement les vols qui redeviennent à l'heure"
                    )
                with _f3:
                    min_gain = st.slider(
                        "Gain minimum (min)",
                        min_value=0, max_value=60, value=0, step=5,
                        help="Filtrer par gain minimal de récupération"
                    )

                # Appliquer les filtres
                df_filtered = df_opt.copy()
                if filter_faisable:
                    df_filtered = df_filtered[df_filtered["Statut"].str.contains("✅|⚠️", na=False)]
                if filter_otp:
                    df_filtered = df_filtered[df_filtered["OTP restauré"].str.contains("✅", na=False)]
                if min_gain > 0:
                    df_filtered = df_filtered[df_filtered["Gain (min)"] >= min_gain]

                st.write(f"**{len(df_filtered)} vol(s)** sur {_n_tot} correspondent aux critères")

                _cols_show = [c for c in [
                    "Vol", "Route", "Avion A1", "Type",
                    "Retard moyen (min)", "Candidats valides",
                    "Meilleur A2", "Statut", "Nouveau départ",
                    "Gain (min)", "Nouveau retard (min)",
                    "OTP restauré", "Conflit A2 suivant", "Équipage",
                    "Vols A1 libérés",
                ] if c in df_filtered.columns]

                _sc = [c for c in ["Statut","OTP restauré","Conflit A2 suivant","Équipage"]
                       if c in _cols_show]
                _gc = [c for c in ["Gain (min)"] if c in _cols_show]
                _nc = [c for c in ["Retard moyen (min)","Nouveau retard (min)","Gain (min)"]
                       if c in _cols_show]

                st.dataframe(
                    df_filtered[_cols_show].style
                        .map(_color_statut_opt, subset=_sc)
                        .map(_color_gain_opt,   subset=_gc)
                        .format({c: "{:.1f}" for c in _nc}),
                    use_container_width=True, hide_index=True,
                    height=min(460, 80 + len(df_filtered) * 40),
                )
                st.caption(
                    "**Légende:** ✅ Faisable = substitution valide  |  "
                    "⚠️ Partiel = solution sub-optimale  |  ❌ Pas de candidat disponible"
                )

            # ── Onglet 2 : Fiche détaillée ────────────────
            with _t2:
                _vol_sel = st.selectbox(
                    "Vol à analyser :",
                    [s.flight_id for s in swap_list_opt],
                    format_func=lambda fid: next(
                        (f"{fid} ({s.origin}→{s.destination}) "
                         f"— Retard : {s.mean_arr_delay:.0f} min "
                         f"{'✅' if s.has_solution else '❌'}"
                         for s in swap_list_opt if s.flight_id == fid), fid),
                    key="opt_sel_fiche",
                )
                _sw = next((s for s in swap_list_opt if s.flight_id == _vol_sel), None)
                if _sw:
                    # ── En-tête ──────────────────────────
                    st.markdown(
                        f'<div style="background:#f8fafc;border:1px solid #e2e8f0;'
                        f'border-radius:8px;padding:14px 20px;margin-bottom:14px;">'
                        f'<span style="font-family:Barlow Condensed,sans-serif;'
                        f'font-weight:800;font-size:1.1rem;color:#0f172a;">'
                        f'{_sw.flight_id}</span>'
                        f'&nbsp;&nbsp;<span style="color:#64748b;font-size:0.85rem;">'
                        f'{_sw.origin} → {_sw.destination}</span>'
                        f'&nbsp;|&nbsp;<span style="color:#dc2626;font-weight:700;">'
                        f'Retard moyen : {_sw.mean_arr_delay:.0f} min</span></div>',
                        unsafe_allow_html=True,
                    )

                    if _sw.best is None:
                        st.error("Aucun candidat A2 disponible pour ce vol.")
                    else:
                        _b = _sw.best
                        _otp_ok = _b.new_delay <= otp_thresh

                        # ── Verdict ───────────────────────
                        if not _sw.has_solution:
                            _msg = (f"❌ Infaisable — {_b.infeasibility_reason}")
                            _card = "swap-card-none"
                        elif _otp_ok:
                            _msg = (f"✅ Substitution recommandée — Vol redevient à l'heure "
                                    f"(retard {_b.new_delay:.0f} min ≤ {otp_thresh} min).")
                            _card = "swap-card"
                        else:
                            _msg = (f"⚠️ Substitution partielle — Retard réduit à {_b.new_delay:.0f} min "
                                    f"(gain {_b.delay_saved:.0f} min).")
                            _card = "swap-card-warn"
                        st.markdown(f'<div class="{_card}">{_msg}</div>',
                                    unsafe_allow_html=True)

                        # ── Comparaison avant/après ───────
                        _cb, _ca_arr, _ca = st.columns([5, 1, 5])
                        with _cb:
                            st.markdown(
                                f'<div style="background:#fef2f2;border:1px solid #fca5a5;'
                                f'border-radius:8px;padding:12px 16px;">'
                                f'<b style="color:#dc2626;font-size:0.7rem;letter-spacing:2px;">'
                                f'SANS SUBSTITUTION</b>'
                                f'<div style="margin-top:8px;">'
                                f'Départ prévu : <b>{_mhm_opt(_b.dep_scheduled)}</b> → '
                                f'Réel A1 : <b style="color:#dc2626;">{_mhm_opt(_b.dep_original)}'
                                f' (+{_b.dep_original-_b.dep_scheduled:.0f} min)</b>'
                                f'</div>'
                                f'<div style="margin-top:4px;font-size:0.75rem;color:#6b7280;">'
                                f'Avion : {_b.a1_msn} | Arrivée : {_mhm_opt(_b.arr_original)}'
                                f'</div></div>',
                                unsafe_allow_html=True,
                            )
                        with _ca_arr:
                            st.markdown(
                                '<div style="text-align:center;font-size:2rem;'
                                'color:#1d4ed8;padding-top:8px;">⇒</div>',
                                unsafe_allow_html=True,
                            )
                        _oc = "#16a34a" if _otp_ok else "#d97706"
                        with _ca:
                            st.markdown(
                                f'<div style="background:#f0fdf4;border:1px solid #86efac;'
                                f'border-radius:8px;padding:12px 16px;">'
                                f'<b style="color:#16a34a;font-size:0.7rem;letter-spacing:2px;">'
                                f'AVEC A2 = {_b.a2_msn}</b>'
                                f'<div style="margin-top:8px;">'
                                f'Départ prévu : <b>{_mhm_opt(_b.dep_scheduled)}</b> → '
                                f'Nouveau : <b style="color:{_oc};">{_mhm_opt(_b.new_dep)}'
                                f' (+{_b.new_delay:.0f} min)</b>'
                                f'</div>'
                                f'<div style="margin-top:4px;font-size:0.75rem;color:#6b7280;">'
                                f'Avion : {_b.a2_msn} | Arrivée : {_mhm_opt(_b.new_arr)} | '
                                f'<b style="color:#16a34a;">Gain : +{_b.delay_saved:.0f} min</b>'
                                f'</div></div>',
                                unsafe_allow_html=True,
                            )

                        # ── Vérifications ─────────────────
                        st.markdown("")
                        st.markdown("**Vérifications**")
                        _v1, _v2, _v3 = st.columns(3)
                        with _v1:
                            _a2ok = not _b.a2_next_conflict
                            _a2dt = (f"Marge +{_b.a2_conflict_margin:.0f} min sur {_b.a2_next_fid}"
                                     if _b.a2_next_fid and _a2ok
                                     else (_b.infeasibility_reason[:60] if not _a2ok
                                           else "Aucun vol suivant"))
                            st.markdown(
                                f'<div style="padding:10px;background:#f8fafc;'
                                f'border:1px solid #e2e8f0;border-radius:8px;">'
                                f'<div style="font-weight:700;color:{"#16a34a" if _a2ok else "#dc2626"};">'
                                f'{"✅" if _a2ok else "❌"} Prochain vol A2</div>'
                                f'<div style="font-size:0.72rem;color:#64748b;margin-top:4px;">'
                                f'{_a2dt}</div></div>', unsafe_allow_html=True)
                        with _v2:
                            st.markdown(
                                f'<div style="padding:10px;background:#f8fafc;'
                                f'border:1px solid #e2e8f0;border-radius:8px;">'
                                f'<div style="font-weight:700;color:#16a34a;">'
                                f'✅ Rotation A1 ({_b.a1_downstream} vol(s) aval)</div>'
                                f'<div style="font-size:0.72rem;color:#64748b;margin-top:4px;">'
                                f'Gain chaîne estimé : ~{_b.a1_chain_delay_saved:.0f} min'
                                f'</div></div>', unsafe_allow_html=True)
                        with _v3:
                            st.markdown(
                                f'<div style="padding:10px;background:#f8fafc;'
                                f'border:1px solid #e2e8f0;border-radius:8px;">'
                                f'<div style="font-weight:700;'
                                f'color:{"#16a34a" if _b.crew_ok else "#dc2626"};">'
                                f'{"✅" if _b.crew_ok else "⚠️"} Équipage</div>'
                                f'<div style="font-size:0.72rem;color:#64748b;margin-top:4px;">'
                                f'{_b.crew_note[:70]}</div></div>', unsafe_allow_html=True)

                    # ── Candidats infaisables (optionnel) ──
                    if show_infeasible_opt and _sw.all_candidates:
                        st.markdown("**Tous les candidats A2**")
                        _rows_c = [{
                            "Avion A2": c.a2_msn, "Prêt à": _mhm_opt(c.a2_last_arr + c.turnaround_used),
                            "Nouveau départ": _mhm_opt(c.new_dep),
                            "Gain (min)": round(c.delay_saved, 1),
                            "Nouveau retard": round(c.new_delay, 1),
                            "Conflit A2+1": "⚠️" if c.a2_next_conflict else "✅",
                            "Équipage": "✅" if c.crew_ok else "⚠️",
                            "Faisable": "✅" if c.feasible else "❌",
                            "Score": round(c.score, 1),
                            "Raison rejet": c.infeasibility_reason if not c.feasible else "—",
                        } for c in _sw.all_candidates]
                        st.dataframe(
                            pd.DataFrame(_rows_c).sort_values("Score", ascending=False),
                            use_container_width=True, hide_index=True,
                            height=min(280, 60 + len(_rows_c) * 38),
                        )

            # ── Onglet 3 : Graphiques ─────────────────────
            with _t3:
                # Avant / après
                _fig_ba = go.Figure()
                _fig_ba.add_trace(go.Bar(
                    name="Retard avant", x=df_opt["Vol"],
                    y=df_opt["Retard prévu (min)"],
                    marker_color="#f87171", opacity=0.85,
                ))
                _fig_ba.add_trace(go.Bar(
                    name="Retard après", x=df_opt["Vol"],
                    y=df_opt["Nouveau retard (min)"],
                    marker_color=["#4ade80" if v <= otp_thresh else "#fb923c"
                                  for v in df_opt["Nouveau retard (min)"]],
                    opacity=0.85,
                ))
                _fig_ba.add_hline(
                    y=otp_thresh, line_dash="dash", line_color="#1d4ed8",
                    annotation_text=f"  Seuil OTP {otp_thresh} min",
                    annotation_font_color="#1d4ed8",
                )
                _fig_ba.update_layout(
                    template="plotly_white", height=320, barmode="group",
                    xaxis_title="Vol", yaxis_title="Retard départ (min)",
                    margin=dict(l=10, r=10, t=30, b=50),
                    legend=dict(orientation="h", yanchor="top", y=1.12, font=dict(size=10)),
                    paper_bgcolor="white", plot_bgcolor="#fafafa",
                    font=dict(family="Barlow, sans-serif"),
                    title=dict(text="<b>Retard avant / après substitution</b>",
                               font=dict(size=12)),
                )
                _fig_ba.update_xaxes(showgrid=False, tickangle=-30)
                _fig_ba.update_yaxes(showgrid=True, gridcolor="#eee")
                st.plotly_chart(_fig_ba, use_container_width=True)

                # Camembert faisabilité
                _pc1, _pc2 = st.columns([1, 2])
                with _pc1:
                    _n_pie_ok  = sum(1 for s in swap_list_opt
                                     if s.has_solution and s.best.new_delay <= otp_thresh)
                    _n_pie_par = sum(1 for s in swap_list_opt
                                     if s.has_solution and s.best.new_delay > otp_thresh)
                    _n_pie_no  = sum(1 for s in swap_list_opt if not s.has_solution)
                    _fig_p = go.Figure(go.Pie(
                        labels=["OTP restauré ✅", "Retard réduit ⚠️", "Aucun swap ❌"],
                        values=[_n_pie_ok, _n_pie_par, _n_pie_no],
                        marker=dict(colors=["#4ade80", "#fb923c", "#f87171"]),
                        textinfo="label+percent", hole=0.45,
                        textfont=dict(size=11),
                    ))
                    _fig_p.update_layout(
                        height=260, margin=dict(l=10, r=10, t=30, b=10),
                        paper_bgcolor="white", showlegend=False,
                        font=dict(family="Barlow, sans-serif"),
                        title=dict(text="<b>Couverture</b>", font=dict(size=11)),
                    )
                    st.plotly_chart(_fig_p, use_container_width=True)
                with _pc2:
                    _xs = [s.original_delay for s in swap_list_opt if s.best]
                    _ys = [s.best.delay_saved for s in swap_list_opt if s.best]
                    _cs = ["#4ade80" if s.best.feasible else "#fb923c"
                           for s in swap_list_opt if s.best]
                    _ls = [s.flight_id for s in swap_list_opt if s.best]
                    _fig_sc = go.Figure()
                    _fig_sc.add_trace(go.Scatter(
                        x=_xs, y=_ys, mode="markers+text",
                        marker=dict(color=_cs, size=14, opacity=0.85,
                                    line=dict(width=1.5, color="white")),
                        text=_ls, textposition="top center",
                        textfont=dict(size=9),
                        hovertemplate="<b>%{text}</b><br>Retard : %{x:.0f} min<br>Gain : %{y:.0f} min<extra></extra>",
                    ))
                    _fig_sc.update_layout(
                        template="plotly_white", height=260,
                        xaxis_title="Retard original (min)", yaxis_title="Gain swap (min)",
                        margin=dict(l=10, r=10, t=30, b=40),
                        paper_bgcolor="white", plot_bgcolor="#fafafa",
                        font=dict(family="Barlow, sans-serif"),
                        title=dict(text="<b>Gain vs retard initial</b>", font=dict(size=11)),
                    )
                    _fig_sc.update_xaxes(showgrid=True, gridcolor="#eee")
                    _fig_sc.update_yaxes(showgrid=True, gridcolor="#eee")
                    st.plotly_chart(_fig_sc, use_container_width=True)

                # ── Onglet 4 : Résumé d'Exécution ─────────────────────
                with _t4:
                    st.markdown("####  Résumé et Recommandations")

                    # Résultats clés
                    col1, col2 = st.columns(2)

                    with col1:
                        st.markdown("#####  Efficacité de la Substitution")
                        if _n_ok > 0:
                            st.success(f"✅ **{_n_ok} solution(s) trouvée(s)** ({_rate:.1f}% de couverture)")
                            st.info(f" Parmi celles-ci: **{_n_otp}** retrouvent l'OTP (< {otp_thresh} min)")
                        else:
                            st.warning("❌ Aucune solution de substitution possible")

                    with col2:
                        st.markdown("##### ⏱️ Impact sur les Retards")
                        if _n_ok > 0:
                            avg_gain = _gain / _n_ok
                            st.success(f"⏱️ **Gain total: {_gain:.0f} minutes**")
                            st.info(f" Gain moyen par vol: {avg_gain:.1f} min")
                            st.metric("Réduction moyenne du retard", f"{(avg_gain/45)*100:.1f}%", help="Sur retard de base ~45 min")
                        else:
                            st.warning("Pas de gain sans solution")

                    st.divider()

                    st.markdown("#####  Détails des Candidats Trouvés")
                    detail_col1, detail_col2, detail_col3 = st.columns(3)

                    with detail_col1:
                        feasible_count = sum(1 for s in swap_list_opt if s.n_candidates_feasible > 0)
                        st.metric(
                            "Vols avec candidats viables",
                            feasible_count,
                            f"{(feasible_count/_n_tot*100):.0f}% des vols analysés"
                        )

                    with detail_col2:
                        avg_candidates = sum(s.n_candidates_found for s in swap_list_opt) / len(swap_list_opt) if swap_list_opt else 0
                        st.metric(
                            "Candidats testés par vol",
                            f"{avg_candidates:.1f}",
                            help="Moyenne d'avions vérifiés"
                        )

                    with detail_col3:
                        infeasible_count = _n_tot - _n_ok
                        st.metric(
                            "Vols sans solution",
                            infeasible_count,
                            f"{(infeasible_count/_n_tot*100):.0f}% sans substitution"
                        )

                    st.divider()

                    st.markdown("#####  Analyse des Contraintes Principales")

                    # Analyser les raisons d'infaisabilité
                    infeas_reasons = defaultdict(int)
                    for s in swap_list_opt:
                        if not s.has_solution and s.best:
                            reason = s.best.infeasibility_reason[:50]
                            infeas_reasons[reason] += 1

                    if infeas_reasons:
                        st.write("**Obstacles à la substitution (TOP 5):**")
                        sorted_reasons = sorted(infeas_reasons.items(), key=lambda x: -x[1])[:5]
                        for reason, count in sorted_reasons:
                            st.write(f"- {reason}… ({count} vols)")

                    st.divider()

                    st.markdown("#####  Recommandations")

                    reco_col1, reco_col2 = st.columns(2)

                    with reco_col1:
                        st.success("✅ **Actions Recommandées:**")
                        st.write("""
                        1. **Implémenter les {_n_ok} substitutions faisables** 
                           → Gain immédiat de {_gain:.0f} minutes

                        2. **Réduire les turnarounds** 
                           → Ajouter plus de flexibilité

                        3. **Pré-positionner les avions** 
                           → Avoir plus d'options par aéroport
                        """.format(_n_ok=_n_ok, _gain=_gain))

                    with reco_col2:
                        st.info("ℹ️ **Points d'Amélioration:**")
                        st.write("""
                        - {infeas_pct:.0f}% des vols n'ont pas de solution
                        - Identifier les aéroports critiques
                        - Ajuster les rotations d'équipage
                        - Augmenter la diversité de flotte
                        """.format(infeas_pct=(100*infeasible_count/_n_tot)))

    else:
        st.info("ℹ️ Lancez l'analyse pour voir les résultats de substitution")

    st.divider()

#
# EXPORT
#
#
# EXPORT
#
dcol1, _ = st.columns([1, 3])
with dcol1:
    export_df = df_agg.copy()
    if hub_airport:
        export_df["hub_congestion_airport"] = hub_airport
        export_df["hub_congestion_factor"]  = hub_factor
    if slack_config:
        export_df["slack_minutes"] = slack_config.get("minutes", 0)
        export_df["slack_scope"]   = slack_config.get("scope", "")
    st.download_button(
        "Exporter les résultats (CSV)",
        data=export_df.to_csv(index=False).encode("utf-8"),
        file_name="AIR_ROBUST_RAM_resultats.csv",
        mime="text/csv",
        use_container_width=True,
    )

