# SECTION HUB CONGESTION — ANALYSE DE L'IMPACT
# ══════════════════════════════════════════════════════════════
if hub_airport:
    section_header_hub(f"Impact de la Congestion Hub — {hub_airport}")

    df_hub_vols   = df_agg[df_agg["hub_affected"] == True]
    df_other_vols = df_agg[df_agg["hub_affected"] == False]

    n_hub       = len(df_hub_vols)
    otp_hub     = float(df_hub_vols["otp_rate"].mean())         if n_hub > 0 else 0.0
    otp_other   = float(df_other_vols["otp_rate"].mean())       if len(df_other_vols) > 0 else 0.0
    delay_hub   = float(df_hub_vols["mean_arr_delay"].mean())   if n_hub > 0 else 0.0
    delay_other = float(df_other_vols["mean_arr_delay"].mean()) if len(df_other_vols) > 0 else 0.0
    p95_hub     = float(df_hub_vols["p95_arr_delay"].mean())    if n_hub > 0 else 0.0
    otp_delta   = otp_hub - otp_other

    hk1, hk2, hk3, hk4 = st.columns(4)
    hk1.markdown(kpi_card_hub(f"Vols au départ de {hub_airport}", str(n_hub), f"Sur {len(df_agg)} vols au total"), unsafe_allow_html=True)
    hk2.markdown(kpi_card_hub("OTP hub vs réseau", f"{otp_hub:.1f} % / {otp_other:.1f} %", f"Écart : {otp_delta:+.1f} pts"), unsafe_allow_html=True)
    hk3.markdown(kpi_card_hub("Retard moy. au départ du hub", f"{delay_hub:.1f} min", f"Réseau hors hub : {delay_other:.1f} min"), unsafe_allow_html=True)
    hk4.markdown(kpi_card_hub("Retard P95 hub", f"{p95_hub:.1f} min", f"Facteur congestion : {hub_factor:.1f}×"), unsafe_allow_html=True)

    st.markdown("")

    if n_hub > 0:
        dest_cols = st.columns([3, 2])

        with dest_cols[0]:
            st.caption(f"**Retard moyen et taux OTP par destination** depuis **{hub_airport}**")
            df_by_dest = (
                df_hub_vols.groupby("destination")
                .agg(mean_delay=("mean_arr_delay","mean"), p95_delay=("p95_arr_delay","mean"),
                     otp_dest=("otp_rate","mean"), n_vols=("flight_id","count"))
                .reset_index().sort_values("mean_delay", ascending=False)
            )
            def dest_bar_color(d):
                if d <= 10: return "#27ae60"
                if d <= 25: return "#f39c12"
                if d <= 60: return "#e67e22"
                return "#e74c3c"
            fig_dest = go.Figure()
            fig_dest.add_trace(go.Bar(
                x=df_by_dest["destination"], y=df_by_dest["mean_delay"],
                marker_color=[dest_bar_color(d) for d in df_by_dest["mean_delay"]],
                text=df_by_dest["mean_delay"].apply(lambda x: f"{x:.0f} min"),
                textposition="outside",
                customdata=np.column_stack([df_by_dest["otp_dest"].round(1), df_by_dest["n_vols"], df_by_dest["p95_delay"].round(1)]),
                hovertemplate="<b>%{x}</b><br>Retard moyen arrivée : <b>%{y:.1f} min</b><br>Retard P95 : %{customdata[2]} min<br>OTP : %{customdata[0]} %<br>Vols concernés : %{customdata[1]}<extra></extra>",
            ))
            fig_dest.update_layout(template="plotly_white", height=320, xaxis_title=f"Destination depuis {hub_airport}", yaxis_title="Retard moyen arrivée (min)", margin=dict(l=10,r=10,t=20,b=60), paper_bgcolor="white", plot_bgcolor="#fafafa", font=dict(family="Barlow, sans-serif"), showlegend=False)
            fig_dest.update_xaxes(showgrid=False, tickangle=-35)
            fig_dest.update_yaxes(showgrid=True, gridcolor="#eee")
            st.plotly_chart(fig_dest, use_container_width=True)

        with dest_cols[1]:
            st.caption(f"**Comparaison OTP** : vols depuis **{hub_airport}** vs reste du réseau")
            df_compare = pd.DataFrame({"Segment":[f"Vols depuis {hub_airport}","Reste du réseau"], "OTP (%)":[otp_hub,otp_other], "Retard moy (min)":[delay_hub,delay_other]})
            fig_cmp = go.Figure()
            fig_cmp.add_trace(go.Bar(x=df_compare["Segment"], y=df_compare["OTP (%)"], marker_color=["#e67e22","#1a6fa0"], text=df_compare["OTP (%)"].apply(lambda x: f"{x:.1f} %"), textposition="outside", hovertemplate="<b>%{x}</b><br>OTP : %{y:.1f} %<extra></extra>"))
            fig_cmp.update_layout(template="plotly_white", height=240, yaxis_title="Taux OTP (%)", yaxis_range=[0,115], margin=dict(l=10,r=10,t=10,b=20), paper_bgcolor="white", plot_bgcolor="#fafafa", font=dict(family="Barlow, sans-serif"), showlegend=False)
            fig_cmp.update_xaxes(showgrid=False); fig_cmp.update_yaxes(showgrid=True, gridcolor="#eee")
            st.plotly_chart(fig_cmp, use_container_width=True)
            fig_cmp2 = go.Figure()
            fig_cmp2.add_trace(go.Bar(x=df_compare["Segment"], y=df_compare["Retard moy (min)"], marker_color=["#e67e22","#1a6fa0"], text=df_compare["Retard moy (min)"].apply(lambda x: f"{x:.1f} min"), textposition="outside", hovertemplate="<b>%{x}</b><br>Retard moy. : %{y:.1f} min<extra></extra>"))
            fig_cmp2.update_layout(template="plotly_white", height=200, yaxis_title="Retard moy. arrivée (min)", margin=dict(l=10,r=10,t=10,b=20), paper_bgcolor="white", plot_bgcolor="#fafafa", font=dict(family="Barlow, sans-serif"), showlegend=False)
            fig_cmp2.update_xaxes(showgrid=False); fig_cmp2.update_yaxes(showgrid=True, gridcolor="#eee")
            st.plotly_chart(fig_cmp2, use_container_width=True)

        st.caption(f"**Détail vol par vol** depuis **{hub_airport}**")
        df_hub_detail = (
            df_hub_vols[["flight_id","destination","scheduled_departure","aircraft_msn","aircraft_type","mean_arr_delay","p95_arr_delay","otp_rate","propagation_idx"]]
            .rename(columns={"flight_id":"Vol","destination":"Destination","scheduled_departure":"Depart prevu","aircraft_msn":"Avion","aircraft_type":"Type","mean_arr_delay":"Retard moy. (min)","p95_arr_delay":"Retard P95 (min)","otp_rate":"OTP (%)","propagation_idx":"Indice propagation"})
            .sort_values("Retard moy. (min)", ascending=False)
        )
        st.dataframe(
            df_hub_detail.style
                .map(color_delay, subset=["Retard moy. (min)"])
                .format({"Retard moy. (min)":"{:.1f}","Retard P95 (min)":"{:.1f}","OTP (%)":"{:.1f}","Indice propagation":"{:.2f}"}),
            use_container_width=True, hide_index=True, height=min(400, 80+len(df_hub_detail)*38),
        )
    else:
        st.info(f"Aucun vol au départ de **{hub_airport}** trouvé dans le programme.")

    st.divider()


# ══════════════════════════════════════════════════════════════
# SECTION OPTIMISEUR — SUBSTITUTION D'AVION
# ══════════════════════════════════════════════════════════════
if "sim_results" in st.session_state:

    def _mhm_opt(m):
        m = int(m) % 1440
        return f"{m//60:02d}:{m%60:02d}"

    def _kpi_opt(label, value, delta=""):
        delta_html = f'<div class="kpi-delta">{delta}</div>' if delta else ""
        return f"""<div class="kpi-card-opt">
            <div class="kpi-value">{value}</div>
            <div class="kpi-label">{label}</div>
            {delta_html}</div>"""

    def _color_statut_opt(val):
        if "✅" in str(val): return "color:#16a34a; font-weight:700"
        if "⚠️" in str(val): return "color:#d97706; font-weight:700"
        if "❌" in str(val): return "color:#dc2626; font-weight:700"
        return ""

    def _color_gain_opt(val):
        try:
            v = float(val)
            if v > 20: return "color:#16a34a; font-weight:700"
            if v > 5:  return "color:#2dd4bf; font-weight:600"
            return "color:#6b7280"
        except: return ""

    st.markdown('<div class="section-header-opt"> Optimiseur — Substitution d\'Avion</div>',
                unsafe_allow_html=True)

    # ── Activation du scénario ─────────────────────────────
    _enable_col, _info_col = st.columns([1, 3])
    with _enable_col:
        enable_optimizer = st.checkbox(
            " Activer l'optimiseur",
            value=False,
            help="Cochez pour activer l'analyse de substitution d'avion",
            key="enable_optimizer_checkbox"
        )

    with _info_col:
        if enable_optimizer:
            st.success("✅ Mode optimiseur **ACTIVÉ** — Analysez les vols retardés")
        else:
            st.info("ℹ️ Mode optimiseur **DÉSACTIVÉ** — Activez pour analyser les substitutions")

    # Exécuter l'optimiseur seulement s'il est activé
    if enable_optimizer:
        # ── Paramètres ────────────────────────────────────────
        with st.expander("⚙️ Paramètres de l'optimiseur", expanded=True):
            _p1, _p2, _p3 = st.columns([1.5, 1.5, 1])

            with _p1:
                delay_threshold_opt = st.slider(
                    " Seuil de déclenchement (min)",
                    min_value=10,
                    max_value=120,
                    value=30,
                    step=5,
                    help="Ne traiter que les vols avec retard moyen arrivée ≥ ce seuil",
                )

            with _p2:
                st.metric(
                    "Vols analysables",
                    int((df_agg["mean_arr_delay"] >= delay_threshold_opt).sum()),
                    help="Nombre de vols avec retard ≥ seuil"
                )

            with _p3:
                show_infeasible_opt = st.checkbox(
                    " Afficher infaisables",
                    value=False,
                    help="Montrer aussi les swaps impossible (pour comprendre pourquoi)",
                )

        # ── Bouton de lancement ────────────────────────────────
        st.markdown("")
        _launch_col, _clear_col, _spacer = st.columns([1, 1, 2])

        with _launch_col:
            launch_analysis = st.button(
                " Lancer l'analyse de substitution",
                key="launch_optimizer_button",
                use_container_width=True,
                type="primary",
                help="Analyser les avions retardés et trouver les meilleures substitutions"
            )

        with _clear_col:
            if st.button(" Réinitialiser", key="reset_optimizer_button", use_container_width=True):
                if "optimizer_results" in st.session_state:
                    del st.session_state.optimizer_results
                st.rerun()

        # ── Exécuter l'analyse si le bouton est cliqué ──────────
        if launch_analysis:
            n_delayed_opt = int((df_agg["mean_arr_delay"] >= delay_threshold_opt).sum())

            if n_delayed_opt == 0:
                st.warning(f"⚠️ Aucun vol ne dépasse {delay_threshold_opt} min de retard moyen. "
                          f"Réduisez le seuil pour analyser plus de vols.")
            else:
                with st.spinner(f" Analyse de {n_delayed_opt} vol(s) en retard… (cela peut prendre quelques secondes)"):
                    df_opt, swap_list_opt = run_swap_optimizer(
                        df_agg=df_agg, all_results=all_results,
                        df_sched=df_sched, df_crew=df_crew,
                        min_turnaround=mt, otp_threshold=otp_thresh,
                        delay_threshold=delay_threshold_opt,
                    )

                    # Sauvegarder les résultats dans la session
                    st.session_state.optimizer_results = {
                        "df_opt": df_opt,
                        "swap_list_opt": swap_list_opt,
                        "delay_threshold_opt": delay_threshold_opt,
                        "show_infeasible_opt": show_infeasible_opt,
                        "n_delayed_opt": n_delayed_opt,
                    }

                st.success("✅ Analyse terminée!")
                st.rerun()

        # ── Afficher les résultats s'ils existent ──────────────
        if "optimizer_results" in st.session_state:
            res = st.session_state.optimizer_results
            df_opt = res["df_opt"]
            swap_list_opt = res["swap_list_opt"]
            show_infeasible_opt = res.get("show_infeasible_opt", False)

            if not df_opt.empty:
                # ── KPI globaux ──────────────────────────────
                st.markdown("###  Résumé de l'Analyse")
                st.divider()

                _n_tot  = len(swap_list_opt)
                _n_ok   = sum(1 for s in swap_list_opt if s.has_solution)
                _n_otp  = sum(1 for s in swap_list_opt
                              if s.has_solution and s.best.new_delay <= otp_thresh)
                _gain   = sum(s.best.delay_saved for s in swap_list_opt if s.has_solution)
                _rate   = _n_ok / _n_tot * 100 if _n_tot else 0

                _ok1, _ok2, _ok3, _ok4 = st.columns(4)
                with _ok1:
                    st.metric(
                        " Vols Analysés",
                        _n_tot,
                        f"Retard ≥ {res['delay_threshold_opt']} min",
                        delta_color="off"
                    )
                with _ok2:
                    st.metric(
                        "✅ Substitutions Faisables",
                        f"{_n_ok}/{_n_tot}",
                        f"{_rate:.0f}% de couverture"
                    )
                with _ok3:
                    st.metric(
                        " OTP Restauré",
                        f"{_n_otp}",
                        f"< {otp_thresh} min après swap"
                    )
                with _ok4:
                    st.metric(
                        "⏱️ Gain Total",
                        f"{_gain:.0f} min",
                        f"Moy. {_gain/_n_ok:.0f} min/vol" if _n_ok else "—"
                    )

                st.markdown("")
                st.divider()

                # ── Onglets de visualisation ──────────────────────────────
                _t1, _t2, _t3, _t4 = st.tabs([
                    " Tableau Récapitulatif",
                    " Fiche Détaillée par Vol",
                    " Graphiques d'Analyse",
                    " Résumé d'Exécution",
                ])

            # ── Onglet 1 : Tableau ────────────────────────
            with _t1:
                st.markdown("####  Tableau Récapitulatif des Substitutions Possibles")

                # Filtres
                _f1, _f2, _f3 = st.columns([1, 1, 1])
                with _f1:
                    filter_faisable = st.checkbox(
                        "✅ Montrer seulement les faisables",
                        value=True,
                        help="Afficher uniquement les vols avec substitution faisable"
                    )
                with _f2:
                    filter_otp = st.checkbox(
                        " Montrer seulement OTP restauré",
                        value=False,
                        help="Afficher uniquement les vols qui redeviennent à l'heure"
                    )
                with _f3:
                    min_gain = st.slider(
                        "Gain minimum (min)",
                        min_value=0, max_value=60, value=0, step=5,
                        help="Filtrer par gain minimal de récupération"
                    )

                # Appliquer les filtres
                df_filtered = df_opt.copy()
                if filter_faisable:
                    df_filtered = df_filtered[df_filtered["Statut"].str.contains("✅|⚠️", na=False)]
                if filter_otp:
                    df_filtered = df_filtered[df_filtered["OTP restauré"].str.contains("✅", na=False)]
                if min_gain > 0:
                    df_filtered = df_filtered[df_filtered["Gain (min)"] >= min_gain]

                st.write(f"**{len(df_filtered)} vol(s)** sur {_n_tot} correspondent aux critères")

                _cols_show = [c for c in [
                    "Vol", "Route", "Avion A1", "Type",
                    "Retard moyen (min)", "Candidats valides",
                    "Meilleur A2", "Statut", "Nouveau départ",
                    "Gain (min)", "Nouveau retard (min)",
                    "OTP restauré", "Conflit A2 suivant", "Équipage",
                    "Vols A1 libérés",
                ] if c in df_filtered.columns]

                _sc = [c for c in ["Statut","OTP restauré","Conflit A2 suivant","Équipage"]
                       if c in _cols_show]
                _gc = [c for c in ["Gain (min)"] if c in _cols_show]
                _nc = [c for c in ["Retard moyen (min)","Nouveau retard (min)","Gain (min)"]
                       if c in _cols_show]

                st.dataframe(
                    df_filtered[_cols_show].style
                        .map(_color_statut_opt, subset=_sc)
                        .map(_color_gain_opt,   subset=_gc)
                        .format({c: "{:.1f}" for c in _nc}),
                    use_container_width=True, hide_index=True,
                    height=min(460, 80 + len(df_filtered) * 40),
                )
                st.caption(
                    "**Légende:** ✅ Faisable = substitution valide  |  "
                    "⚠️ Partiel = solution sub-optimale  |  ❌ Pas de candidat disponible"
                )

            # ...existing code...

    else:
        st.info("ℹ️ Lancez l'analyse pour voir les résultats de substitution")

    st.divider()


