# SECTION OPTIMISEUR — SUBSTITUTION D'AVION
#
if "sim_results" in st.session_state:

    def _mhm_opt(m):
        m = int(m) % 1440
        return f"{m//60:02d}:{m%60:02d}"

    def _kpi_opt(label, value, delta=""):
        delta_html = f'<div class="kpi-delta">{delta}</div>' if delta else ""
        return f"""<div class="kpi-card-opt">
            <div class="kpi-value">{value}</div>
            <div class="kpi-label">{label}</div>
            {delta_html}</div>"""

    def _color_statut_opt(val):
        if "✅" in str(val): return "color:#16a34a; font-weight:700"
        if "⚠️" in str(val): return "color:#d97706; font-weight:700"
        if "❌" in str(val): return "color:#dc2626; font-weight:700"
        return ""

    def _color_gain_opt(val):
        try:
            v = float(val)
            if v > 20: return "color:#16a34a; font-weight:700"
            if v > 5:  return "color:#2dd4bf; font-weight:600"
            return "color:#6b7280"
        except: return ""

    st.markdown('<div class="section-header-opt"> Optimiseur — Substitution d\'Avion</div>',
                unsafe_allow_html=True)

    # ── Activation du scénario ─────────────────────────────
    _enable_col, _info_col = st.columns([1, 3])
    with _enable_col:
        enable_optimizer = st.checkbox(
            " Activer l'optimiseur",
            value=False,
            help="Cochez pour activer l'analyse de substitution d'avion",
            key="enable_optimizer_checkbox"
        )

    with _info_col:
        if enable_optimizer:
            st.success("✅ Mode optimiseur **ACTIVÉ** — Analysez les vols retardés")
        else:
            st.info("ℹ️ Mode optimiseur **DÉSACTIVÉ** — Activez pour analyser les substitutions")

    # Exécuter l'optimiseur seulement s'il est activé
    if enable_optimizer:
        # ── Paramètres ────────────────────────────────────────
        with st.expander("⚙️ Paramètres de l'optimiseur", expanded=True):
            _p1, _p2, _p3 = st.columns([1.5, 1.5, 1])

            with _p1:
                delay_threshold_opt = st.slider(
                    " Seuil de déclenchement (min)",
                    min_value=10,
                    max_value=120,
                    value=30,
                    step=5,
                    help="Ne traiter que les vols avec retard moyen arrivée ≥ ce seuil",
                )

            with _p2:
                st.metric(
                    "Vols analysables",
                    int((df_agg["mean_arr_delay"] >= delay_threshold_opt).sum()),
                    help="Nombre de vols avec retard ≥ seuil"
                )

            with _p3:
                show_infeasible_opt = st.checkbox(
                    " Afficher infaisables",
                    value=False,
                    help="Montrer aussi les swaps impossible (pour comprendre pourquoi)",
                )

        # ── Bouton de lancement ────────────────────────────────
        st.markdown("")
        _launch_col, _clear_col, _spacer = st.columns([1, 1, 2])

        with _launch_col:
            launch_analysis = st.button(
                " Lancer l'analyse de substitution",
                key="launch_optimizer_button",
                use_container_width=True,
                type="primary",
                help="Analyser les avions retardés et trouver les meilleures substitutions"
            )

        with _clear_col:
            if st.button(" Réinitialiser", key="reset_optimizer_button", use_container_width=True):
                if "optimizer_results" in st.session_state:
                    del st.session_state.optimizer_results
                st.rerun()

        # ── Exécuter l'analyse si le bouton est cliqué ──────────
        if launch_analysis:
            n_delayed_opt = int((df_agg["mean_arr_delay"] >= delay_threshold_opt).sum())

            if n_delayed_opt == 0:
                st.warning(f"⚠️ Aucun vol ne dépasse {delay_threshold_opt} min de retard moyen. "
                          f"Réduisez le seuil pour analyser plus de vols.")
            else:
                with st.spinner(f" Analyse de {n_delayed_opt} vol(s) en retard… (cela peut prendre quelques secondes)"):
                    df_opt, swap_list_opt = run_swap_optimizer(
                        df_agg=df_agg, all_results=all_results,
                        df_sched=df_sched, df_crew=df_crew,
                        min_turnaround=mt, otp_threshold=otp_thresh,
                        delay_threshold=delay_threshold_opt,
                    )

                    # Sauvegarder les résultats dans la session
                    st.session_state.optimizer_results = {
                        "df_opt": df_opt,
                        "swap_list_opt": swap_list_opt,
                        "delay_threshold_opt": delay_threshold_opt,
                        "show_infeasible_opt": show_infeasible_opt,
                        "n_delayed_opt": n_delayed_opt,
                    }

                st.success("✅ Analyse terminée!")
                st.rerun()

        # ── Afficher les résultats s'ils existent ──────────────
        if "optimizer_results" in st.session_state:
            res = st.session_state.optimizer_results
            df_opt = res["df_opt"]
            swap_list_opt = res["swap_list_opt"]
            show_infeasible_opt = res.get("show_infeasible_opt", False)

            if not df_opt.empty:
                # ── KPI globaux ──────────────────────────────
                st.markdown("###  Résumé de l'Analyse")
                st.divider()

                _n_tot  = len(swap_list_opt)
                _n_ok   = sum(1 for s in swap_list_opt if s.has_solution)
                _n_otp  = sum(1 for s in swap_list_opt
                              if s.has_solution and s.best.new_delay <= otp_thresh)
                _gain   = sum(s.best.delay_saved for s in swap_list_opt if s.has_solution)
                _rate   = _n_ok / _n_tot * 100 if _n_tot else 0

                _ok1, _ok2, _ok3, _ok4 = st.columns(4)
                with _ok1:
                    st.metric(
                        " Vols Analysés",
                        _n_tot,
                        f"Retard ≥ {res['delay_threshold_opt']} min",
                        delta_color="off"
                    )
                with _ok2:
                    st.metric(
                        "✅ Substitutions Faisables",
                        f"{_n_ok}/{_n_tot}",
                        f"{_rate:.0f}% de couverture"
                    )
                with _ok3:
                    st.metric(
                        " OTP Restauré",
                        f"{_n_otp}",
                        f"< {otp_thresh} min après swap"
                    )
                with _ok4:
                    st.metric(
                        "⏱️ Gain Total",
                        f"{_gain:.0f} min",
                        f"Moy. {_gain/_n_ok:.0f} min/vol" if _n_ok else "—"
                    )

                st.markdown("")
                st.divider()

                # ── Onglets de visualisation ──────────────────────────────
                _t1, _t2, _t3, _t4 = st.tabs([
                    " Tableau Récapitulatif",
                    " Fiche Détaillée par Vol",
                    " Graphiques d'Analyse",
                    " Résumé d'Exécution",
                ])

            # ── Onglet 1 : Tableau ────────────────────────
            with _t1:
                st.markdown("####  Tableau Récapitulatif des Substitutions Possibles")

                # Filtres
                _f1, _f2, _f3 = st.columns([1, 1, 1])
                with _f1:
                    filter_faisable = st.checkbox(
                        "✅ Montrer seulement les faisables",
                        value=True,
                        help="Afficher uniquement les vols avec substitution faisable"
                    )
                with _f2:
                    filter_otp = st.checkbox(
                        " Montrer seulement OTP restauré",
                        value=False,
                        help="Afficher uniquement les vols qui redeviennent à l'heure"
                    )
                with _f3:
                    min_gain = st.slider(
                        "Gain minimum (min)",
                        min_value=0, max_value=60, value=0, step=5,
                        help="Filtrer par gain minimal de récupération"
                    )

                # Appliquer les filtres
                df_filtered = df_opt.copy()
                if filter_faisable:
                    df_filtered = df_filtered[df_filtered["Statut"].str.contains("✅|⚠️", na=False)]
                if filter_otp:
                    df_filtered = df_filtered[df_filtered["OTP restauré"].str.contains("✅", na=False)]
                if min_gain > 0:
                    df_filtered = df_filtered[df_filtered["Gain (min)"] >= min_gain]

                st.write(f"**{len(df_filtered)} vol(s)** sur {_n_tot} correspondent aux critères")

                _cols_show = [c for c in [
                    "Vol", "Route", "Avion A1", "Type",
                    "Retard moyen (min)", "Candidats valides",
                    "Meilleur A2", "Statut", "Nouveau départ",
                    "Gain (min)", "Nouveau retard (min)",
                    "OTP restauré", "Conflit A2 suivant", "Équipage",
                    "Vols A1 libérés",
                ] if c in df_filtered.columns]

                _sc = [c for c in ["Statut","OTP restauré","Conflit A2 suivant","Équipage"]
                       if c in _cols_show]
                _gc = [c for c in ["Gain (min)"] if c in _cols_show]
                _nc = [c for c in ["Retard moyen (min)","Nouveau retard (min)","Gain (min)"]
                       if c in _cols_show]

                st.dataframe(
                    df_filtered[_cols_show].style
                        .map(_color_statut_opt, subset=_sc)
                        .map(_color_gain_opt,   subset=_gc)
                        .format({c: "{:.1f}" for c in _nc}),
                    use_container_width=True, hide_index=True,
                    height=min(460, 80 + len(df_filtered) * 40),
                )
                st.caption(
                    "**Légende:** ✅ Faisable = substitution valide  |  "
                    "⚠️ Partiel = solution sub-optimale  |  ❌ Pas de candidat disponible"
                )

            # ── Onglet 2 : Fiche détaillée ────────────────
            with _t2:
                _vol_sel = st.selectbox(
                    "Vol à analyser :",
                    [s.flight_id for s in swap_list_opt],
                    format_func=lambda fid: next(
                        (f"{fid} ({s.origin}→{s.destination}) "
                         f"— Retard : {s.mean_arr_delay:.0f} min "
                         f"{'✅' if s.has_solution else '❌'}"
                         for s in swap_list_opt if s.flight_id == fid), fid),
                    key="opt_sel_fiche",
                )
                _sw = next((s for s in swap_list_opt if s.flight_id == _vol_sel), None)
                if _sw:
                    # ── En-tête ──────────────────────────
                    st.markdown(
                        f'<div style="background:#f8fafc;border:1px solid #e2e8f0;'
                        f'border-radius:8px;padding:14px 20px;margin-bottom:14px;">'
                        f'<span style="font-family:Barlow Condensed,sans-serif;'
                        f'font-weight:800;font-size:1.1rem;color:#0f172a;">'
                        f'{_sw.flight_id}</span>'
                        f'&nbsp;&nbsp;<span style="color:#64748b;font-size:0.85rem;">'
                        f'{_sw.origin} → {_sw.destination}</span>'
                        f'&nbsp;|&nbsp;<span style="color:#dc2626;font-weight:700;">'
                        f'Retard moyen : {_sw.mean_arr_delay:.0f} min</span></div>',
                        unsafe_allow_html=True,
                    )

                    if _sw.best is None:
                        st.error("Aucun candidat A2 disponible pour ce vol.")
                    else:
                        _b = _sw.best
                        _otp_ok = _b.new_delay <= otp_thresh

                        # ── Verdict ───────────────────────
                        if not _sw.has_solution:
                            _msg = (f"❌ Infaisable — {_b.infeasibility_reason}")
                            _card = "swap-card-none"
                        elif _otp_ok:
                            _msg = (f"✅ Substitution recommandée — Vol redevient à l'heure "
                                    f"(retard {_b.new_delay:.0f} min ≤ {otp_thresh} min).")
                            _card = "swap-card"
                        else:
                            _msg = (f"⚠️ Substitution partielle — Retard réduit à {_b.new_delay:.0f} min "
                                    f"(gain {_b.delay_saved:.0f} min).")
                            _card = "swap-card-warn"
                        st.markdown(f'<div class="{_card}">{_msg}</div>',
                                    unsafe_allow_html=True)

                        # ── Comparaison avant/après ───────
                        _cb, _ca_arr, _ca = st.columns([5, 1, 5])
                        with _cb:
                            st.markdown(
                                f'<div style="background:#fef2f2;border:1px solid #fca5a5;'
                                f'border-radius:8px;padding:12px 16px;">'
                                f'<b style="color:#dc2626;font-size:0.7rem;letter-spacing:2px;">'
                                f'SANS SUBSTITUTION</b>'
                                f'<div style="margin-top:8px;">'
                                f'Départ prévu : <b>{_mhm_opt(_b.dep_scheduled)}</b> → '
                                f'Réel A1 : <b style="color:#dc2626;">{_mhm_opt(_b.dep_original)}'
                                f' (+{_b.dep_original-_b.dep_scheduled:.0f} min)</b>'
                                f'</div>'
                                f'<div style="margin-top:4px;font-size:0.75rem;color:#6b7280;">'
                                f'Avion : {_b.a1_msn} | Arrivée : {_mhm_opt(_b.arr_original)}'
                                f'</div></div>',
                                unsafe_allow_html=True,
                            )
                        with _ca_arr:
                            st.markdown(
                                '<div style="text-align:center;font-size:2rem;'
                                'color:#1d4ed8;padding-top:8px;">⇒</div>',
                                unsafe_allow_html=True,
                            )
                        _oc = "#16a34a" if _otp_ok else "#d97706"
                        with _ca:
                            st.markdown(
                                f'<div style="background:#f0fdf4;border:1px solid #86efac;'
                                f'border-radius:8px;padding:12px 16px;">'
                                f'<b style="color:#16a34a;font-size:0.7rem;letter-spacing:2px;">'
                                f'AVEC A2 = {_b.a2_msn}</b>'
                                f'<div style="margin-top:8px;">'
                                f'Départ prévu : <b>{_mhm_opt(_b.dep_scheduled)}</b> → '
                                f'Nouveau : <b style="color:{_oc};">{_mhm_opt(_b.new_dep)}'
                                f' (+{_b.new_delay:.0f} min)</b>'
                                f'</div>'
                                f'<div style="margin-top:4px;font-size:0.75rem;color:#6b7280;">'
                                f'Avion : {_b.a2_msn} | Arrivée : {_mhm_opt(_b.new_arr)} | '
                                f'<b style="color:#16a34a;">Gain : +{_b.delay_saved:.0f} min</b>'
                                f'</div></div>',
                                unsafe_allow_html=True,
                            )

                        # ── Vérifications ─────────────────
                        st.markdown("")
                        st.markdown("**Vérifications**")
                        _v1, _v2, _v3 = st.columns(3)
                        with _v1:
                            _a2ok = not _b.a2_next_conflict
                            _a2dt = (f"Marge +{_b.a2_conflict_margin:.0f} min sur {_b.a2_next_fid}"
                                     if _b.a2_next_fid and _a2ok
                                     else (_b.infeasibility_reason[:60] if not _a2ok
                                           else "Aucun vol suivant"))
                            st.markdown(
                                f'<div style="padding:10px;background:#f8fafc;'
                                f'border:1px solid #e2e8f0;border-radius:8px;">'
                                f'<div style="font-weight:700;color:{"#16a34a" if _a2ok else "#dc2626"};">'
                                f'{"✅" if _a2ok else "❌"} Prochain vol A2</div>'
                                f'<div style="font-size:0.72rem;color:#64748b;margin-top:4px;">'
                                f'{_a2dt}</div></div>', unsafe_allow_html=True)
                        with _v2:
                            st.markdown(
                                f'<div style="padding:10px;background:#f8fafc;'
                                f'border:1px solid #e2e8f0;border-radius:8px;">'
                                f'<div style="font-weight:700;color:#16a34a;">'
                                f'✅ Rotation A1 ({_b.a1_downstream} vol(s) aval)</div>'
                                f'<div style="font-size:0.72rem;color:#64748b;margin-top:4px;">'
                                f'Gain chaîne estimé : ~{_b.a1_chain_delay_saved:.0f} min'
                                f'</div></div>', unsafe_allow_html=True)
                        with _v3:
                            st.markdown(
                                f'<div style="padding:10px;background:#f8fafc;'
                                f'border:1px solid #e2e8f0;border-radius:8px;">'
                                f'<div style="font-weight:700;'
                                f'color:{"#16a34a" if _b.crew_ok else "#dc2626"};">'
                                f'{"✅" if _b.crew_ok else "⚠️"} Équipage</div>'
                                f'<div style="font-size:0.72rem;color:#64748b;margin-top:4px;">'
                                f'{_b.crew_note[:70]}</div></div>', unsafe_allow_html=True)

                    # ── Candidats infaisables (optionnel) ──
                    if show_infeasible_opt and _sw.all_candidates:
                        st.markdown("**Tous les candidats A2**")
                        _rows_c = [{
                            "Avion A2": c.a2_msn, "Prêt à": _mhm_opt(c.a2_last_arr + c.turnaround_used),
                            "Nouveau départ": _mhm_opt(c.new_dep),
                            "Gain (min)": round(c.delay_saved, 1),
                            "Nouveau retard": round(c.new_delay, 1),
                            "Conflit A2+1": "⚠️" if c.a2_next_conflict else "✅",
                            "Équipage": "✅" if c.crew_ok else "⚠️",
                            "Faisable": "✅" if c.feasible else "❌",
                            "Score": round(c.score, 1),
                            "Raison rejet": c.infeasibility_reason if not c.feasible else "—",
                        } for c in _sw.all_candidates]
                        st.dataframe(
                            pd.DataFrame(_rows_c).sort_values("Score", ascending=False),
                            use_container_width=True, hide_index=True,
                            height=min(280, 60 + len(_rows_c) * 38),
                        )

            # ── Onglet 3 : Graphiques ─────────────────────
            with _t3:
                # Avant / après
                _fig_ba = go.Figure()
                _fig_ba.add_trace(go.Bar(
                    name="Retard avant", x=df_opt["Vol"],
                    y=df_opt["Retard prévu (min)"],
                    marker_color="#f87171", opacity=0.85,
                ))
                _fig_ba.add_trace(go.Bar(
                    name="Retard après", x=df_opt["Vol"],
                    y=df_opt["Nouveau retard (min)"],
                    marker_color=["#4ade80" if v <= otp_thresh else "#fb923c"
                                  for v in df_opt["Nouveau retard (min)"]],
                    opacity=0.85,
                ))
                _fig_ba.add_hline(
                    y=otp_thresh, line_dash="dash", line_color="#1d4ed8",
                    annotation_text=f"  Seuil OTP {otp_thresh} min",
                    annotation_font_color="#1d4ed8",
                )
                _fig_ba.update_layout(
                    template="plotly_white", height=320, barmode="group",
                    xaxis_title="Vol", yaxis_title="Retard départ (min)",
                    margin=dict(l=10, r=10, t=30, b=50),
                    legend=dict(orientation="h", yanchor="top", y=1.12, font=dict(size=10)),
                    paper_bgcolor="white", plot_bgcolor="#fafafa",
                    font=dict(family="Barlow, sans-serif"),
                    title=dict(text="<b>Retard avant / après substitution</b>",
                               font=dict(size=12)),
                )
                _fig_ba.update_xaxes(showgrid=False, tickangle=-30)
                _fig_ba.update_yaxes(showgrid=True, gridcolor="#eee")
                st.plotly_chart(_fig_ba, use_container_width=True)

                # Camembert faisabilité
                _pc1, _pc2 = st.columns([1, 2])
                with _pc1:
                    _n_pie_ok  = sum(1 for s in swap_list_opt
                                     if s.has_solution and s.best.new_delay <= otp_thresh)
                    _n_pie_par = sum(1 for s in swap_list_opt
                                     if s.has_solution and s.best.new_delay > otp_thresh)
                    _n_pie_no  = sum(1 for s in swap_list_opt if not s.has_solution)
                    _fig_p = go.Figure(go.Pie(
                        labels=["OTP restauré ✅", "Retard réduit ⚠️", "Aucun swap ❌"],
                        values=[_n_pie_ok, _n_pie_par, _n_pie_no],
                        marker=dict(colors=["#4ade80", "#fb923c", "#f87171"]),
                        textinfo="label+percent", hole=0.45,
                        textfont=dict(size=11),
                    ))
                    _fig_p.update_layout(
                        height=260, margin=dict(l=10, r=10, t=30, b=10),
                        paper_bgcolor="white", showlegend=False,
                        font=dict(family="Barlow, sans-serif"),
                        title=dict(text="<b>Couverture</b>", font=dict(size=11)),
                    )
                    st.plotly_chart(_fig_p, use_container_width=True)
                with _pc2:
                    _xs = [s.original_delay for s in swap_list_opt if s.best]
                    _ys = [s.best.delay_saved for s in swap_list_opt if s.best]
                    _cs = ["#4ade80" if s.best.feasible else "#fb923c"
                           for s in swap_list_opt if s.best]
                    _ls = [s.flight_id for s in swap_list_opt if s.best]
                    _fig_sc = go.Figure()
                    _fig_sc.add_trace(go.Scatter(
                        x=_xs, y=_ys, mode="markers+text",
                        marker=dict(color=_cs, size=14, opacity=0.85,
                                    line=dict(width=1.5, color="white")),
                        text=_ls, textposition="top center",
                        textfont=dict(size=9),
                        hovertemplate="<b>%{text}</b><br>Retard : %{x:.0f} min<br>Gain : %{y:.0f} min<extra></extra>",
                    ))
                    _fig_sc.update_layout(
                        template="plotly_white", height=260,
                        xaxis_title="Retard original (min)", yaxis_title="Gain swap (min)",
                        margin=dict(l=10, r=10, t=30, b=40),
                        paper_bgcolor="white", plot_bgcolor="#fafafa",
                        font=dict(family="Barlow, sans-serif"),
                        title=dict(text="<b>Gain vs retard initial</b>", font=dict(size=11)),
                    )
                    _fig_sc.update_xaxes(showgrid=True, gridcolor="#eee")
                    _fig_sc.update_yaxes(showgrid=True, gridcolor="#eee")
                    st.plotly_chart(_fig_sc, use_container_width=True)

                # ── Onglet 4 : Résumé d'Exécution ─────────────────────
                with _t4:
                    st.markdown("####  Résumé et Recommandations")

                    # Résultats clés
                    col1, col2 = st.columns(2)

                    with col1:
                        st.markdown("#####  Efficacité de la Substitution")
                        if _n_ok > 0:
                            st.success(f"✅ **{_n_ok} solution(s) trouvée(s)** ({_rate:.1f}% de couverture)")
                            st.info(f" Parmi celles-ci: **{_n_otp}** retrouvent l'OTP (< {otp_thresh} min)")
                        else:
                            st.warning("❌ Aucune solution de substitution possible")

                    with col2:
                        st.markdown("##### ⏱️ Impact sur les Retards")
                        if _n_ok > 0:
                            avg_gain = _gain / _n_ok
                            st.success(f"⏱️ **Gain total: {_gain:.0f} minutes**")
                            st.info(f" Gain moyen par vol: {avg_gain:.1f} min")
                            st.metric("Réduction moyenne du retard", f"{(avg_gain/45)*100:.1f}%", help="Sur retard de base ~45 min")
                        else:
                            st.warning("Pas de gain sans solution")

                    st.divider()

                    st.markdown("#####  Détails des Candidats Trouvés")
                    detail_col1, detail_col2, detail_col3 = st.columns(3)

                    with detail_col1:
                        feasible_count = sum(1 for s in swap_list_opt if s.n_candidates_feasible > 0)
                        st.metric(
                            "Vols avec candidats viables",
                            feasible_count,
                            f"{(feasible_count/_n_tot*100):.0f}% des vols analysés"
                        )

                    with detail_col2:
                        avg_candidates = sum(s.n_candidates_found for s in swap_list_opt) / len(swap_list_opt) if swap_list_opt else 0
                        st.metric(
                            "Candidats testés par vol",
                            f"{avg_candidates:.1f}",
                            help="Moyenne d'avions vérifiés"
                        )

                    with detail_col3:
                        infeasible_count = _n_tot - _n_ok
                        st.metric(
                            "Vols sans solution",
                            infeasible_count,
                            f"{(infeasible_count/_n_tot*100):.0f}% sans substitution"
                        )

                    st.divider()

                    st.markdown("#####  Analyse des Contraintes Principales")

                    # Analyser les raisons d'infaisabilité
                    infeas_reasons = defaultdict(int)
                    for s in swap_list_opt:
                        if not s.has_solution and s.best:
                            reason = s.best.infeasibility_reason[:50]
                            infeas_reasons[reason] += 1

                    if infeas_reasons:
                        st.write("**Obstacles à la substitution (TOP 5):**")
                        sorted_reasons = sorted(infeas_reasons.items(), key=lambda x: -x[1])[:5]
                        for reason, count in sorted_reasons:
                            st.write(f"- {reason}… ({count} vols)")

                    st.divider()

                    st.markdown("#####  Recommandations")

                    reco_col1, reco_col2 = st.columns(2)

                    with reco_col1:
                        st.success("✅ **Actions Recommandées:**")
                        st.write("""
                        1. **Implémenter les {_n_ok} substitutions faisables** 
                           → Gain immédiat de {_gain:.0f} minutes

                        2. **Réduire les turnarounds** 
                           → Ajouter plus de flexibilité

                        3. **Pré-positionner les avions** 
                           → Avoir plus d'options par aéroport
                        """.format(_n_ok=_n_ok, _gain=_gain))

                    with reco_col2:
                        st.info("ℹ️ **Points d'Amélioration:**")
                        st.write("""
                        - {infeas_pct:.0f}% des vols n'ont pas de solution
                        - Identifier les aéroports critiques
                        - Ajuster les rotations d'équipage
                        - Augmenter la diversité de flotte
                        """.format(infeas_pct=(100*infeasible_count/_n_tot)))

    else:
        st.info("ℹ️ Lancez l'analyse pour voir les résultats de substitution")

    st.divider()

#
# EXPORT
#
#
# EXPORT
#
dcol1, _ = st.columns([1, 3])
with dcol1:
    export_df = df_agg.copy()
    if hub_airport:
        export_df["hub_congestion_airport"] = hub_airport
        export_df["hub_congestion_factor"]  = hub_factor
    if slack_config:
        export_df["slack_minutes"] = slack_config.get("minutes", 0)
        export_df["slack_scope"]   = slack_config.get("scope", "")
    st.download_button(
        "Exporter les résultats (CSV)",
        data=export_df.to_csv(index=False).encode("utf-8"),
        file_name="AIR_ROBUST_RAM_resultats.csv",
        mime="text/csv",
        use_container_width=True,
    )

"""
src/data_loader.py — Chargement et validation des données
"""
import pandas as pd
import numpy as np
import streamlit as st
import re

# ─── Colonnes obligatoires (format interne simulateur) ───────
REQUIRED_SCHEDULE = {
    "flight_id", "origin", "destination",
    "scheduled_departure", "scheduled_arrival",
    "aircraft_msn", "aircraft_type",
}
REQUIRED_CREW = {
    "crew_id", "flight_sequence",
}
REQUIRED_REF = {
    "param_type", "value",
}

# ─── Colonnes clés pour détecter le format opérationnel ──────
OPS_LEG_COLS = {"FN_CARRIER", "FN_NUMBER", "DEP_AP_SCHED", "ARR_AP_SCHED"}
OPS_DOA_COLS = {"CREW_ID", "ACTIVITY", "ACTIVITY_GROUP", "ORIGINE"}

# ─── Référentiel route domestique ────────────────────────────
DOM = {
    "CMN", "RAK", "AGA", "TNG", "FEZ", "RBA", "OUD", "NDR",
    "EUN", "VIL", "TTU", "OZZ", "ERH", "ESU", "AHU", "GLN",
    "MEK", "TTA", "OZG",
}

# ─── Utilitaires horaires ────────────────────────────────────

def hhmm_to_minutes(t: str) -> int:
    try:
        h, m = map(int, str(t).strip().split(":"))
        return h * 60 + m
    except Exception:
        return 0


def minutes_to_hhmm(minutes: int) -> str:
    h = (int(minutes) // 60) % 24
    m = int(minutes) % 60
    return f"{h:02d}:{m:02d}"


def _normalize_date_series(series: pd.Series) -> pd.Series:
    """Normalise en YYYY-MM-DD sans inverser les formats ISO (YYYY-MM-DD)."""
    s = series.astype(str).str.strip()
    iso_mask = s.str.match(r"^\d{4}-\d{2}-\d{2}$", na=False)

    out = pd.Series(index=series.index, dtype="object")
    out.loc[iso_mask] = pd.to_datetime(
        s.loc[iso_mask], errors="coerce", dayfirst=False
    ).dt.strftime("%Y-%m-%d")
    out.loc[~iso_mask] = pd.to_datetime(
        s.loc[~iso_mask], errors="coerce", dayfirst=True
    ).dt.strftime("%Y-%m-%d")
    return out


def _to_date_str(series: pd.Series) -> pd.Series:
    """
    Convertit n'importe quelle série (Timestamp, str, mixed) en YYYY-MM-DD.
    Méthode unique et robuste utilisée par _recompute_crew_constraints.
    """
    dt = pd.to_datetime(series, errors="coerce")
    if isinstance(dt, pd.Series):
        return dt.dt.strftime("%Y-%m-%d")
    if isinstance(dt, pd.DatetimeIndex):
        idx = series.index if isinstance(series, pd.Series) else None
        return pd.Series(dt.strftime("%Y-%m-%d"), index=idx)
    return pd.Series(pd.to_datetime([series], errors="coerce")).dt.strftime("%Y-%m-%d")


def _normalize_flight_token(value) -> str:
    """Normalise un identifiant vol unitaire ; retourne "" si invalide."""
    if pd.isna(value):
        return ""

    raw = str(value).strip().upper()
    if not raw:
        return ""
    if raw in {"NAN", "NONE", "NULL", "<NA>", "NAT"}:
        return ""
    try:
        f = float(raw)
        if np.isfinite(f) and f.is_integer():
            raw = str(int(f))
    except (ValueError, TypeError):
        pass

    raw = re.sub(r"\s+", "", raw)
    raw = re.sub(r"[^A-Z0-9]", "", raw)
    if not raw or raw in {"NAN", "NONE", "NULL", "NA"}:
        return ""
    return raw


def _normalize_flight_sequence(value) -> str:
    """Nettoie une séquence 'A;B;C' et supprime les tokens invalides."""
    tokens = []
    for tok in str(value).split(";"):
        t = _normalize_flight_token(tok)
        if t:
            tokens.append(t)
    return ";".join(tokens)


# ─── Lecture brute d'un fichier uploadé ──────────────────────

def _read_file(uploaded_file) -> pd.DataFrame | None:
    if uploaded_file is None:
        return None
    try:
        name = uploaded_file.name.lower()
        uploaded_file.seek(0)
        if name.endswith((".xlsx", ".xls")):
            def _sanitize_columns(df: pd.DataFrame) -> pd.DataFrame:
                if df is None:
                    return df
                out = df.copy()
                cols = []
                for c in out.columns:
                    s = "" if pd.isna(c) else str(c).strip()
                    cols.append(s)
                out.columns = cols
                drop_cols = [c for c in out.columns if not c or c.lower().startswith("unnamed")]
                if drop_cols:
                    out = out.drop(columns=drop_cols, errors="ignore")
                return out

            def _sheet_score(df: pd.DataFrame) -> tuple[int, int, int, int]:
                if df is None:
                    return (-1, -1, -1, -1)
                cols = [str(c).strip() for c in df.columns if str(c).strip()]
                colset = set(cols)

                known_hits = len(colset & (
                    REQUIRED_SCHEDULE
                    | REQUIRED_CREW
                    | REQUIRED_REF
                    | OPS_LEG_COLS
                    | OPS_DOA_COLS
                ))
                non_empty_cols = len(cols)
                n_rows = int(len(df))
                data_size = n_rows * max(non_empty_cols, 1)
                return (known_hits, non_empty_cols, n_rows, data_size)

            best_df = None
            best_score = (-1, -1, -1, -1)
            uploaded_file.seek(0)
            xls = pd.ExcelFile(uploaded_file)

            for sh in xls.sheet_names:
                for header_row in range(0, 8):
                    try:
                        sdf = pd.read_excel(xls, sheet_name=sh, header=header_row)
                    except Exception:
                        continue
                    sdf = _sanitize_columns(sdf)
                    score = _sheet_score(sdf)
                    if score > best_score:
                        best_df = sdf
                        best_score = score

            if best_df is not None:
                return best_df

            uploaded_file.seek(0)
            return pd.read_excel(uploaded_file)
        try:
            uploaded_file.seek(0)
            df = pd.read_csv(uploaded_file, sep=",")
            if df.shape[1] > 1:
                return df
        except Exception:
            pass
        uploaded_file.seek(0)
        return pd.read_csv(uploaded_file, sep=";")
    except Exception as e:
        st.error(f"Impossible de lire **{uploaded_file.name}** : {e}")
        return None


# ─── Validation des colonnes ─────────────────────────────────

def _check_columns(df: pd.DataFrame, required: set, label: str) -> bool:
    missing = required - set(df.columns)
    if missing:
        st.error(
            f"Le fichier **{label}** ne contient pas les colonnes requises :\n\n"
            f"`{', '.join(sorted(missing))}`\n\n"
            f"Colonnes trouvées : `{', '.join(df.columns.tolist())}`"
        )
        return False
    return True


# ══════════════════════════════════════════════════════════════
# Détection et conversion du format opérationnel
# ══════════════════════════════════════════════════════════════

def _is_ops_leg(df: pd.DataFrame) -> bool:
    return OPS_LEG_COLS.issubset(set(df.columns))


def _is_ops_doa(df: pd.DataFrame) -> bool:
    return OPS_DOA_COLS.issubset(set(df.columns))


def _convert_leg_futur(df: pd.DataFrame) -> pd.DataFrame:
    """
    Convertit LEG_FUTUR -> format schedule interne.
    Toutes les colonnes originales sont conservees dans le DataFrame.
    """
    if "LEG_STATE" in df.columns:
        df = df[df["LEG_STATE"] == "NEW"].copy()
    else:
        df = df.copy()

    if "DAY_OF_ORIGIN" in df.columns:
        df["DAY_OF_ORIGIN"] = (
            df["DAY_OF_ORIGIN"]
            .astype(str)
            .str.strip()
            .str.replace(",", "", regex=False)
            .str.replace(" ", "", regex=False)
            .str.replace(r"\.0+$", "", regex=True)
            .str.extract(r"(\d{8})", expand=False)
            .fillna("")
        )

    carriers = df["FN_CARRIER"].apply(_normalize_flight_token)
    numbers  = df["FN_NUMBER"].apply(_normalize_flight_token)
    df["flight_id"] = [
        (f"{c}{n}" if c and n and any(ch.isdigit() for ch in f"{c}{n}")
         else (n if (not c and n and any(ch.isdigit() for ch in n)) else ""))
        for c, n in zip(carriers, numbers)
    ]
    df["origin"]        = df["DEP_AP_SCHED"]
    df["destination"]   = df["ARR_AP_SCHED"]
    df["aircraft_msn"]  = df["AC_REGISTRATION"]
    df["aircraft_type"] = df["AC_SUBTYPE"].astype(str)

    def _parse_hhmm(value) -> str:
        if pd.isna(value):
            return "0000"
        raw = str(value).strip()
        if not raw:
            return "0000"
        try:
            hhmm_int = int(float(raw))
            hhmm = f"{hhmm_int:04d}"[-4:]
        except (ValueError, TypeError):
            digits = "".join(ch for ch in raw if ch.isdigit())
            if not digits:
                return "0000"
            hhmm = digits[-4:].zfill(4)
        hh = int(hhmm[:2])
        mm = int(hhmm[2:4])
        if hh > 23 or mm > 59:
            return "0000"
        return hhmm

    def _parse_day(value) -> int:
        if pd.isna(value):
            return 0
        raw = str(value).strip()
        if not raw:
            return 0
        try:
            day_val = int(float(raw))
            return day_val % 100
        except (ValueError, TypeError):
            digits = "".join(ch for ch in raw if ch.isdigit())
            if not digits:
                return 0
            return int(digits[-2:])

    dep_t = df["DEP_TIME_SCHED"].apply(_parse_hhmm)
    arr_t = df["ARR_TIME_SCHED"].apply(_parse_hhmm)
    df["scheduled_departure"] = dep_t.str[:2] + ":" + dep_t.str[2:4]
    df["scheduled_arrival"]   = arr_t.str[:2] + arr_t.str[2:4]

    if "DEP_DAY_SCHED" in df.columns:
        dep_day = df["DEP_DAY_SCHED"].apply(_parse_day)
    elif "DAY_OF_ORIGIN" in df.columns:
        dep_day = df["DAY_OF_ORIGIN"].apply(_parse_day)
    else:
        dep_day = pd.Series([0] * len(df), index=df.index)

    if "ARR_DAY_SCHED" in df.columns:
        arr_day = df["ARR_DAY_SCHED"].apply(_parse_day)
    elif "DAY_OF_ORIGIN" in df.columns:
        arr_day = df["DAY_OF_ORIGIN"].apply(_parse_day)
    else:
        arr_day = pd.Series([0] * len(df), index=df.index)

    dep_min = dep_t.apply(lambda x: int(x[:2]) * 60 + int(x[2:4]))
    arr_min = arr_t.apply(lambda x: int(x[:2]) * 60 + int(x[2:4]))
    dur = (arr_day - dep_day) * 1440 + (arr_min - dep_min)
    dur.loc[dur < 0] += 30 * 1440
    df["flight_duration_min"] = dur

    if "DAY_OF_ORIGIN" in df.columns:
        d = df["DAY_OF_ORIGIN"].astype(str)
        df["flight_date"] = (
            d.str[:4] + "-" + d.str[4:6] + "-" + d.str[6:8]
        )
        bad_mask = df["flight_date"].str.contains(r"[^0-9\-]", na=True) | (df["flight_date"].str.len() != 10)
        df.loc[bad_mask, "flight_date"] = ""


    df["origin_city"] = df["origin"]
    df["dest_city"]   = df["destination"]
    df["leg_number"]  = 1
    df["legs_total"]  = 1

    df = df[df["flight_id"].astype(str).str.strip() != ""].copy()

    for _col in ["FN_NUMBER", "DEP_TIME_SCHED", "ARR_TIME_SCHED",
                 "DEP_DAY_SCHED", "ARR_DAY_SCHED", "LEG_SEQUENCE_NUMBER"]:
        if _col in df.columns:
            df[_col] = (
                df[_col]
                .astype(str)
                .str.replace(r"\.0+$", "", regex=True)
                .str.replace(",", "", regex=False)
            )

    return df.reset_index(drop=True)


_EXCEL_EPOCH = pd.Timestamp("1899-12-30")

def _clean_ac_msn(val) -> str:
    if val is None or (isinstance(val, float) and np.isnan(val)):
        return ""
    if isinstance(val, pd.Timestamp):
        serial = (val.normalize() - _EXCEL_EPOCH).days
        return str(serial)
    s = str(val).strip()
    if not s or s in {"nan", "NaT", "None", ""}:
        return ""
    if len(s) >= 10 and s[4] == "-" and s[7] == "-":
        try:
            t = pd.Timestamp(s)
            if t.year < 2000:
                serial = (t.normalize() - _EXCEL_EPOCH).days
                return str(serial)
            return s[:10]
        except Exception:
            pass
    if s.endswith(".0"):
        return s[:-2]
    return s


def _format_date_str(val) -> str:
    if val is None:
        return ""
    if isinstance(val, pd.Timestamp):
        return val.strftime("%Y-%m-%d") if pd.notna(val) else ""
    s = str(val).strip()
    if not s or s in {"nan", "NaT", "None"}:
        return ""
    if "T" in s:
        s = s.split("T")[0]
    return s[:10]


def _convert_doa_programe(df: pd.DataFrame) -> pd.DataFrame:
    """
    Convertit DOA_PROGRAME → format crew_pairing interne.

    Groupement par CREW_ID + DATE_LT (date locale opérationnelle).
    Tri des vols par DATE_LT + START_LT
    Clé de jointure avec le schedule : numéro de vol + date + ORIGINE + DESTINATION.
    """
    df = df.copy()

    # ── Remappage colonnes si nécessaire ──────────────────────
    if {"ACTIVITY_GROUP", "POS"}.issubset(df.columns):
        actg = df["ACTIVITY_GROUP"].astype(str).str.strip().str.upper()
        posv = df["POS"].astype(str).str.strip().str.upper()

        # Détection : POS contient FLT au lieu de ACTIVITY_GROUP
        colonnes_decalees = (not (actg == "FLT").any()) and (posv == "FLT").any()

        if colonnes_decalees:
            src = df.copy()  # snapshot sécurisé

            # Correction principale
            df["ACTIVITY_GROUP"] = src["POS"]

            # Ne pas casser les colonnes métier
            for col in [
                "ACTIVITY", "ORIGINE", "DESTINATION",
                "START_LT", "END_LT", "A_C"
            ]:
                if col in src.columns:
                    df[col] = src[col]

            # Gestion des dates/temps (corriger les manquants)
            if "START_UTC" in src.columns:
                df["START_UTC"] = src["START_UTC"].fillna(src.get("START_LT"))

            if "END_UTC" in src.columns:
                df["END_UTC"] = src["END_UTC"].fillna(src.get("END_LT"))

            # Colonnes optionnelles (sécurisées)
            for col in [
                "LAYOVER", "HOTEL", "BLOCK_HOURS",
                "BLC", "AUGMENTATION",
                "flight_sequence", "rest_sequence_min"
            ]:
                if col in src.columns:
                    df[col] = src[col]

    # Référence date
    _REF_DATE = pd.Timestamp("2000-01-01")

    def _epoch_minutes_lt(row) -> float:
        """
        Ordonne les vols par DATE_LT + START_LT
        """
        try:
            dt = pd.to_datetime(row["DATE_LT"], errors="coerce")
            if pd.isna(dt):
                return 0.0
            day_offset = (dt.normalize() - _REF_DATE).days * 1440

            # ── Heure locale : START_LT prioritaire ──────────
            t = row.get("START_LT")
            if t is None or (isinstance(t, float) and np.isnan(t)):
                return float(day_offset)
            if hasattr(t, "hour"):
                return day_offset + t.hour * 60 + t.minute
            parts = str(t).split(":")
            if len(parts) >= 2:
                try:
                    return day_offset + int(parts[0]) * 60 + int(parts[1])
                except ValueError:
                    pass
            return float(day_offset)
        except Exception:
            return 0.0

    # ── Filtrer les lignes de type FLT ────────────────────────
    df_flt = df[
        df["ACTIVITY_GROUP"].astype(str).str.strip().str.upper() == "FLT"
    ].copy()

    df_flt["_epoch"] = df_flt.apply(_epoch_minutes_lt, axis=1)
    df_flt = df_flt.sort_values(["CREW_ID", "DATE_LT", "_epoch"])

    # ── Groupement par CREW_ID + DATE_LT ─────────────────────
    crew_rows = []

    for (cid, duty_date), grp in df_flt.groupby(
        ["CREW_ID", "DATE_LT"], observed=True, sort=False
    ):
        grp = grp.sort_values("_epoch")

        # Collecter les vols avec leur origine et destination
        fids, origins, dests = [], [], []
        for _, r in grp.iterrows():
            tok = _normalize_flight_token(r["ACTIVITY"])
            if not tok:
                continue
            # Normaliser le numéro de vol (ex: "570" → "AT570")
            if tok.isdigit():
                tok = f"AT{tok}"
            elif not any(ch.isdigit() for ch in tok):
                continue  # Pas un vol (activité sol, etc.)

            fids.append(tok)
            origins.append(
                str(r["ORIGINE"]).strip().upper()
                if "ORIGINE" in grp.columns and pd.notna(r.get("ORIGINE"))
                else ""
            )
            dests.append(
                str(r["DESTINATION"]).strip().upper()
                if "DESTINATION" in grp.columns and pd.notna(r.get("DESTINATION"))
                else ""
            )

        if not fids:
            continue

        # ── Données complémentaires ───────────────────────────
        quals = (
            grp["AC_QUALS"].iloc[0]
            if "AC_QUALS" in grp.columns and not grp["AC_QUALS"].isna().all()
            else ""
        )
        rank     = grp["RANK_"].iloc[0]    if "RANK_" in grp.columns    else ""
        ac_codes = grp["A_C"].dropna().unique() if "A_C" in grp.columns else []
        msn      = _clean_ac_msn(ac_codes[0]) if len(ac_codes) > 0 else ""
        block    = grp["BLOCK_HOURS"].iloc[0] if "BLOCK_HOURS" in grp.columns else ""

        quals_str = str(quals).strip()
        ac_type   = quals_str if quals_str else str(msn)

        duty_start_str = _format_date_str(duty_date)

        # Normaliser l'identifiant équipage
        if pd.isna(cid):
            cid_str = "UNKNOWN"
        elif str(cid).replace(".", "", 1).isdigit():
            cid_str = str(int(float(cid)))
        else:
            cid_str = str(cid).strip()

        date_token = "".join(ch for ch in duty_start_str if ch.isdigit())[:8]
        if not date_token:
            date_token = str(duty_date).strip().replace(" ", "_")

        crew_rows.append({
            "crew_id":              f"CREW-{cid_str}-{date_token}",
            "CREW_ID_OPS":          cid_str,
            "flight_date":          duty_start_str,
            "aircraft_msn":         msn,
            "aircraft_type":        ac_type,
            "flight_sequence":      ";".join(fids),
            "n_flights":            len(fids),
            "RANK_":                rank,
            "AC_QUALS":             quals,
            "BLOCK_HOURS":          block,
            "ORIGINE":              origins[0] if origins else "",
            "DESTINATION":          dests[-1]  if dests   else "",
            # Séquences origine/destination par vol — utilisées pour la jointure 4-clés
            "ORIGINE_SEQUENCE":     ";".join(origins),
            "DESTINATION_SEQUENCE": ";".join(dests),
        })

    return pd.DataFrame(crew_rows)


# ─── Traitement interne du schedule ──────────────────────────

def _process_schedule(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    if "flight_id" in df.columns:
        df["flight_id"] = df["flight_id"].apply(_normalize_flight_token)
        df = df[df["flight_id"] != ""].copy()

    df["dep_min"] = df["scheduled_departure"].apply(hhmm_to_minutes)
    df["arr_min"] = df["scheduled_arrival"].apply(hhmm_to_minutes)

    mask_night = df["arr_min"] < df["dep_min"]
    df.loc[mask_night, "arr_min"] += 1440

    if "flight_duration_min" not in df.columns:
        df["flight_duration_min"] = df["arr_min"] - df["dep_min"]

    if "flight_date" in df.columns:
        dates = pd.to_datetime(df["flight_date"], errors="coerce")
        valid = dates.notna()
        if valid.any():
            j0 = dates.loc[valid].min()
            day_offset = (dates - j0).dt.days.fillna(0).astype(int)
            df["dep_min"] += day_offset * 1440
            df["arr_min"]  = df["dep_min"] + df["flight_duration_min"]

    if "flight_date" not in df.columns: df["flight_date"] = ""
    if "leg_number"  not in df.columns: df["leg_number"]  = 1
    if "legs_total"  not in df.columns: df["legs_total"]  = 1
    return df


def _recompute_crew_constraints(
    df_sched: pd.DataFrame, df_crew: pd.DataFrame
) -> pd.DataFrame:
    """
    Recalcule les séquences crew.

    Cle de jointure : numero de vol + date + origine + destination (4 cles).
    Date utilisee cote equipage : flight_date (issue de DATE_LT, heure locale).

    Note: rest_sequence_min est force a 0 pour ne pas ajouter de repos equipage.
    """
    if "flight_id" not in df_sched.columns:
        return df_crew
    if "crew_id" not in df_crew.columns or "flight_sequence" not in df_crew.columns:
        return df_crew

    # ── 1. Référentiel schedule normalisé ─────────────────────────────────────
    sched = df_sched[["flight_id"]].copy()
    sched["flight_id"]        = sched["flight_id"].astype(str).str.strip().str.upper()
    sched["flight_date_norm"] = (
        _to_date_str(df_sched["flight_date"])
        if "flight_date" in df_sched.columns
        else pd.Series([""] * len(df_sched), index=df_sched.index)
    )
    sched["origin"] = (
        df_sched["origin"].astype(str).str.strip().str.upper()
        if "origin" in df_sched.columns
        else ""
    )
    sched["destination"] = (
        df_sched["destination"].astype(str).str.strip().str.upper()
        if "destination" in df_sched.columns
        else ""
    )

    # ── 2. Exploser les séquences crew (1 ligne par vol) ──────────────────────
    rows = []
    for _, cr in df_crew.iterrows():
        seq_fids = [f.strip() for f in str(cr.get("flight_sequence", "")).split(";")]
        seq_orgs = [x.strip().upper() for x in str(cr.get("ORIGINE_SEQUENCE", "")).split(";")]
        seq_dsts = [x.strip().upper() for x in str(cr.get("DESTINATION_SEQUENCE", "")).split(";")]
        date_norm = _to_date_str(pd.Series([cr.get("flight_date", "")])).iloc[0]

        for i, fid_raw in enumerate(seq_fids):
            fid = str(fid_raw).strip().upper()
            if not fid:
                continue
            org = seq_orgs[i] if i < len(seq_orgs) else ""
            dst = seq_dsts[i] if i < len(seq_dsts) else ""
            rows.append({
                "crew_id":          cr["crew_id"],
                "flight_id":        fid,
                "flight_date_norm": date_norm,
                "origin":           org,
                "destination":      dst,
                "seq_pos":          i,
            })

    if not rows:
        return df_crew

    seq = pd.DataFrame(rows)

    # ── 3. Jointure 4-clés : vol + date + origine + destination ───────────────
    merged = seq.merge(
        sched[["flight_id", "flight_date_norm", "origin", "destination"]],
        on=["flight_id", "flight_date_norm", "origin", "destination"],
        how="left",
    )

    # ── 4. Agreger par crew_id ────────────────────────────────────────────────
    crew_agg = (
        merged.sort_values(["crew_id", "seq_pos"])
        .groupby("crew_id", as_index=False, observed=True)
        .agg(
            rest_sequence_min=(
                "seq_pos",
                lambda s: ";".join("0" for _ in s.tolist()),
            ),
        )
    )

    # ── 5. Fusionner avec df_crew ─────────────────────────────────────────────
    out = df_crew.copy()
    out = out.merge(crew_agg, on="crew_id", how="left")


    return out


def _group_crew_pairs(df_crew: pd.DataFrame) -> pd.DataFrame:
    """
    Fusionne les 2 lignes équipage (CC/CA) en 1 seule ligne par vol.

    Regroupement: flight_sequence + flight_date + ORIGINE + DESTINATION
    (avec fallbacks vers flight_id / origin / destination si disponibles).
    """
    if df_crew is None or df_crew.empty:
        return df_crew

    df = df_crew.copy()

    # Colonnes de regroupement avec fallbacks pour le format DOA
    _fallbacks = {
        "flight_sequence": "flight_id",
        "flight_date":     None,
        "ORIGINE":         "origin",
        "DESTINATION":     "destination",
    }
    group_keys = []
    for primary, fallback in _fallbacks.items():
        if primary in df.columns:
            group_keys.append(primary)
        elif fallback and fallback in df.columns:
            group_keys.append(fallback)

    if not group_keys:
        df["CC_ID"] = df.get("crew_id", "")
        df["CA_ID"] = ""
        df["crew_label"] = df["CC_ID"].astype(str).apply(lambda x: f"CC: {x}")
        return df

    cc_ranks = {"CMD", "CDB", "CC", "CPT", "CAPT", "PIC", "P1"}
    if "RANK_" in df.columns:
        df["_is_cc"] = df["RANK_"].apply(lambda r: str(r).strip().upper() in cc_ranks)
    else:
        df["_sort_num"] = pd.to_numeric(df["crew_id"], errors="coerce").fillna(0)
        df = df.sort_values(group_keys + ["_sort_num"])
        df["_is_cc"] = df.groupby(group_keys, sort=False, observed=True).cumcount() == 0

    rows = []
    for _, grp in df.groupby(group_keys, sort=False, observed=True):
        cc_grp = grp[grp["_is_cc"] == True]
        ca_grp = grp[grp["_is_cc"] == False]

        base  = grp.iloc[0].to_dict()
        cc_id = str(cc_grp["crew_id"].iloc[0]) if not cc_grp.empty else ""
        ca_id = str(ca_grp["crew_id"].iloc[0]) if not ca_grp.empty else ""

        base["CC_ID"]      = cc_id
        base["CA_ID"]      = ca_id
        base["crew_label"] = f"CC: {cc_id} | CA: {ca_id}" if ca_id else f"CC: {cc_id}"
        base["crew_id"]    = f"PAIR-{cc_id}-{ca_id or 'X'}"
        rows.append(base)

    result = pd.DataFrame(rows)
    drop_cols = [c for c in ["_is_cc", "_sort_num"] if c in result.columns]
    if drop_cols:
        result = result.drop(columns=drop_cols)
    return result.reset_index(drop=True)
# ══════════════════════════════════════════════════════════════
# Chargement avec détection automatique du format
# ══════════════════════════════════════════════════════════════

def load_uploaded_data(schedule_file, crew_file, ref_file=None):
    """
    Charge les fichiers uploadés dans Streamlit.
    Détecte automatiquement le format et traduit si nécessaire.
    """
    df_sched_raw = _read_file(schedule_file)
    df_crew_raw  = _read_file(crew_file)
    df_ref       = _read_file(ref_file) if ref_file else None

    if df_sched_raw is None or df_crew_raw is None:
        return None, None, None

    converted_sched = _is_ops_leg(df_sched_raw)
    converted_crew  = _is_ops_doa(df_crew_raw)

    df_sched = _convert_leg_futur(df_sched_raw) if converted_sched else df_sched_raw
    df_crew  = _convert_doa_programe(df_crew_raw) if converted_crew else df_crew_raw

    ok_s = _check_columns(df_sched, REQUIRED_SCHEDULE, schedule_file.name)
    ok_c = _check_columns(df_crew,  REQUIRED_CREW,     crew_file.name)
    if not ok_s or not ok_c:
        return None, None, None

    if df_ref is not None:
        ref_cols_norm = {str(c).strip().lower() for c in df_ref.columns}
        # Evite le message d'erreur "param_type, value" quand un fichier turnaround est chargé ici.
        if REQUIRED_REF.issubset(ref_cols_norm):
            df_ref = df_ref.copy()
            df_ref.columns = [str(c).strip().lower() for c in df_ref.columns]
        elif {"airport", "aircraft_type", "min_turnaround_min"}.issubset(ref_cols_norm):
            st.info(
                f"Le fichier **{ref_file.name}** ressemble à un fichier turnaround. "
                "Les paramètres de référence par défaut seront utilisés."
            )
            df_ref = None
        else:
            _check_columns(df_ref, REQUIRED_REF, ref_file.name)

    df_sched = _process_schedule(df_sched)
    if "flight_sequence" in df_crew.columns:
        df_crew = df_crew.copy()
        df_crew["flight_sequence"] = df_crew["flight_sequence"].fillna("").apply(_normalize_flight_sequence)
        df_crew = df_crew[df_crew["flight_sequence"] != ""].copy()

    if "flight_sequence" in df_crew.columns and "rest_sequence_min" not in df_crew.columns:
        df_crew = _recompute_crew_constraints(df_sched, df_crew)
    elif converted_crew:
        df_crew = _recompute_crew_constraints(df_sched, df_crew)

    df_crew = _group_crew_pairs(df_crew)

    return df_sched, df_crew, df_ref


# ─── Chargement du fichier turnaround CSV ────────────────────

def load_turnaround_table(uploaded_file) -> dict:
    """
    Charge le fichier CSV/Excel turnaround uploadé via Streamlit.

    Format attendu : airport, aircraft_type, min_turnaround_min
    Retourne un dict avec clés (airport, aircraft_type) → minutes.
    La ligne (DEFAULT, DEFAULT) sert de valeur par défaut globale.

    Hiérarchie de lookup (dans _resolve_min_turnaround) :
      1. (airport, aircraft_type)   — correspondance exacte

    """
    if uploaded_file is None:
        return {}

    df = _read_file(uploaded_file)
    if df is None or df.empty:
        st.warning("Fichier turnaround vide ou illisible — valeurs par défaut utilisées.")
        return {}

    required = {"airport", "aircraft_type", "min_turnaround_min"}
    raw_cols = [str(c).strip() for c in df.columns]
    raw_to_norm = {c: c.lower() for c in raw_cols}

    alias_map = {
        "airport": {
            "airport", "aeroport", "apt", "station", "origin", "dep_ap_sched",
        },
        "aircraft_type": {
            "aircraft_type", "ac_type", "aircraft", "type_avion", "fleet", "ac_subtype",
        },
        "min_turnaround_min": {
            "min_turnaround_min", "min_turnaround", "turnaround_min", "tat_min",
        },
    }

    rename_dict = {}
    taken_targets = set()
    for raw, norm in raw_to_norm.items():
        for target, aliases in alias_map.items():
            if norm in aliases and target not in taken_targets:
                rename_dict[raw] = target
                taken_targets.add(target)
                break

    df = df.rename(columns=rename_dict)
    df.columns = [str(c).strip().lower() for c in df.columns]

    missing = required - set(df.columns)
    if missing:
        st.error(
            "Le fichier turnaround doit contenir les colonnes : "
            "`airport, aircraft_type, min_turnaround_min`\n\n"
            f"Colonnes manquantes : `{', '.join(sorted(missing))}`\n\n"
            f"Colonnes trouvées : `{', '.join([str(c) for c in raw_cols])}`"
        )
        return {}

    table = {}
    for _, row in df.iterrows():
        airport = str(row["airport"]).strip().upper()
        ac_type = str(row["aircraft_type"]).strip().upper()
        try:
            minutes = float(str(row["min_turnaround_min"]).replace(",", "."))
        except (ValueError, TypeError):
            continue
        table[(airport, ac_type)] = minutes

    return table


# ─── Extraction paramètres de référence ──────────────────────

def build_ref_dicts(df_ref, turnaround_table=None):
    """
    Retourne les paramètres de simulation.

    Si turnaround_table est fourni (dict issu du CSV uploadé),
    il est retourné tel quel en 6ème position.
    Sinon, un fallback DEFAULT est utilisé.

    Retourne: (min_turnaround, gamma_shape, gamma_scale,
               markov_matrix, markov_multipliers, turnaround_table)
    """
    min_turnaround = {
        "DEFAULT": 45.0,
    }
    gamma_shape        = 2.5
    gamma_scale        = 15.0
    markov_matrix      = np.array([
        [0.65, 0.28, 0.07],
        [0.25, 0.52, 0.23],
        [0.08, 0.28, 0.64],
    ])
    markov_multipliers = [1.0, 1.45, 2.30]

    if turnaround_table is None:
        turnaround_table = {}

    if df_ref is None or "param_type" not in df_ref.columns:
        return min_turnaround, gamma_shape, gamma_scale, \
               markov_matrix, markov_multipliers, turnaround_table

    states = {"Normal": 0, "Alerte": 1, "Bloqué": 2}

    for _, row in df_ref.iterrows():
        pt  = str(row.get("param_type", "")).strip()
        at  = str(row.get("aircraft_type", "")).strip()
        try:
            val = float(row.get("value", 0))
        except (ValueError, TypeError):
            continue

        if pt == "min_turnaround_min":
            pass
        elif pt == "gamma_shape":
            gamma_shape = val
        elif pt == "gamma_scale":
            gamma_scale = val
        elif pt == "markov_transition":
            try:
                src, dst = at.split("→")
                i = states[src.strip()]
                j = states[dst.strip()]
                markov_matrix[i, j] = val
            except Exception:
                pass
        elif pt == "markov_turnaround_multiplier_normal":
            markov_multipliers[0] = val
        elif pt == "markov_turnaround_multiplier_alerte":
            markov_multipliers[1] = val
        elif pt == "markov_turnaround_multiplier_bloque":
            markov_multipliers[2] = val

    return min_turnaround, gamma_shape, gamma_scale, \
           markov_matrix, markov_multipliers, turnaround_table


if __name__ == "__main__":
    mt, gs, gsc, mm, mp, tt = build_ref_dicts(None)
    print("data_loader: defaults OK")
    print(f"Turnaround DEFAULT={mt.get('DEFAULT', 45.0)}")

"""
src/data_loader.py — Chargement et validation des données
"""
import pandas as pd
import numpy as np
import streamlit as st
import re

# ─── Colonnes obligatoires (format interne simulateur) ───────
REQUIRED_SCHEDULE = {
    "flight_id", "origin", "destination",
    "scheduled_departure", "scheduled_arrival",
    "aircraft_msn", "aircraft_type",
}
REQUIRED_CREW = {
    "crew_id", "flight_sequence",
}
REQUIRED_REF = {
    "param_type", "value",
}

# ─── Colonnes clés pour détecter le format opérationnel ──────
OPS_LEG_COLS = {"FN_CARRIER", "FN_NUMBER", "DEP_AP_SCHED", "ARR_AP_SCHED"}
OPS_DOA_COLS = {"CREW_ID", "ACTIVITY", "ACTIVITY_GROUP", "ORIGINE"}

# ─── Référentiel route domestique ────────────────────────────
DOM = {
    "CMN", "RAK", "AGA", "TNG", "FEZ", "RBA", "OUD", "NDR",
    "EUN", "VIL", "TTU", "OZZ", "ERH", "ESU", "AHU", "GLN",
    "MEK", "TTA", "OZG",
}

# ─── Utilitaires horaires ────────────────────────────────────

def hhmm_to_minutes(t: str) -> int:
    try:
        h, m = map(int, str(t).strip().split(":"))
        return h * 60 + m
    except Exception:
        return 0


def minutes_to_hhmm(minutes: int) -> str:
    h = (int(minutes) // 60) % 24
    m = int(minutes) % 60
    return f"{h:02d}:{m:02d}"


def _normalize_date_series(series: pd.Series) -> pd.Series:
    """Normalise en YYYY-MM-DD sans inverser les formats ISO (YYYY-MM-DD)."""
    s = series.astype(str).str.strip()
    iso_mask = s.str.match(r"^\d{4}-\d{2}-\d{2}$", na=False)

    out = pd.Series(index=series.index, dtype="object")
    out.loc[iso_mask] = pd.to_datetime(
        s.loc[iso_mask], errors="coerce", dayfirst=False
    ).dt.strftime("%Y-%m-%d")
    out.loc[~iso_mask] = pd.to_datetime(
        s.loc[~iso_mask], errors="coerce", dayfirst=True
    ).dt.strftime("%Y-%m-%d")
    return out


def _to_date_str(series: pd.Series) -> pd.Series:
    """
    Convertit n'importe quelle série (Timestamp, str, mixed) en YYYY-MM-DD.
    Méthode unique et robuste utilisée par _recompute_crew_constraints.
    """
    dt = pd.to_datetime(series, errors="coerce")
    if isinstance(dt, pd.Series):
        return dt.dt.strftime("%Y-%m-%d")
    if isinstance(dt, pd.DatetimeIndex):
        idx = series.index if isinstance(series, pd.Series) else None
        return pd.Series(dt.strftime("%Y-%m-%d"), index=idx)
    return pd.Series(pd.to_datetime([series], errors="coerce")).dt.strftime("%Y-%m-%d")


def _normalize_flight_token(value) -> str:
    """Normalise un identifiant vol unitaire ; retourne "" si invalide."""
    if pd.isna(value):
        return ""

    raw = str(value).strip().upper()
    if not raw:
        return ""
    if raw in {"NAN", "NONE", "NULL", "<NA>", "NAT"}:
        return ""
    try:
        f = float(raw)
        if np.isfinite(f) and f.is_integer():
            raw = str(int(f))
    except (ValueError, TypeError):
        pass

    raw = re.sub(r"\s+", "", raw)
    raw = re.sub(r"[^A-Z0-9]", "", raw)
    if not raw or raw in {"NAN", "NONE", "NULL", "NA"}:
        return ""
    return raw


def _normalize_flight_sequence(value) -> str:
    """Nettoie une séquence 'A;B;C' et supprime les tokens invalides."""
    tokens = []
    for tok in str(value).split(";"):
        t = _normalize_flight_token(tok)
        if t:
            tokens.append(t)
    return ";".join(tokens)


# ─── Lecture brute d'un fichier uploadé ──────────────────────

def _read_file(uploaded_file) -> pd.DataFrame | None:
    if uploaded_file is None:
        return None
    try:
        name = uploaded_file.name.lower()
        uploaded_file.seek(0)
        if name.endswith((".xlsx", ".xls")):
            def _sanitize_columns(df: pd.DataFrame) -> pd.DataFrame:
                if df is None:
                    return df
                out = df.copy()
                cols = []
                for c in out.columns:
                    s = "" if pd.isna(c) else str(c).strip()
                    cols.append(s)
                out.columns = cols
                drop_cols = [c for c in out.columns if not c or c.lower().startswith("unnamed")]
                if drop_cols:
                    out = out.drop(columns=drop_cols, errors="ignore")
                return out

            def _sheet_score(df: pd.DataFrame) -> tuple[int, int, int, int]:
                if df is None:
                    return (-1, -1, -1, -1)
                cols = [str(c).strip() for c in df.columns if str(c).strip()]
                colset = set(cols)

                known_hits = len(colset & (
                    REQUIRED_SCHEDULE
                    | REQUIRED_CREW
                    | REQUIRED_REF
                    | OPS_LEG_COLS
                    | OPS_DOA_COLS
                ))
                non_empty_cols = len(cols)
                n_rows = int(len(df))
                data_size = n_rows * max(non_empty_cols, 1)
                return (known_hits, non_empty_cols, n_rows, data_size)

            best_df = None
            best_score = (-1, -1, -1, -1)
            uploaded_file.seek(0)
            xls = pd.ExcelFile(uploaded_file)

            for sh in xls.sheet_names:
                for header_row in range(0, 8):
                    try:
                        sdf = pd.read_excel(xls, sheet_name=sh, header=header_row)
                    except Exception:
                        continue
                    sdf = _sanitize_columns(sdf)
                    score = _sheet_score(sdf)
                    if score > best_score:
                        best_df = sdf
                        best_score = score

            if best_df is not None:
                return best_df

            uploaded_file.seek(0)
            return pd.read_excel(uploaded_file)
        try:
            uploaded_file.seek(0)
            df = pd.read_csv(uploaded_file, sep=",")
            if df.shape[1] > 1:
                return df
        except Exception:
            pass
        uploaded_file.seek(0)
        return pd.read_csv(uploaded_file, sep=";")
    except Exception as e:
        st.error(f"Impossible de lire **{uploaded_file.name}** : {e}")
        return None


# ─── Validation des colonnes ─────────────────────────────────

def _check_columns(df: pd.DataFrame, required: set, label: str) -> bool:
    missing = required - set(df.columns)
    if missing:
        st.error(
            f"Le fichier **{label}** ne contient pas les colonnes requises :\n\n"
            f"`{', '.join(sorted(missing))}`\n\n"
            f"Colonnes trouvées : `{', '.join(df.columns.tolist())}`"
        )
        return False
    return True


# ══════════════════════════════════════════════════════════════
# Détection et conversion du format opérationnel
# ══════════════════════════════════════════════════════════════

def _is_ops_leg(df: pd.DataFrame) -> bool:
    return OPS_LEG_COLS.issubset(set(df.columns))


def _is_ops_doa(df: pd.DataFrame) -> bool:
    return OPS_DOA_COLS.issubset(set(df.columns))


def _convert_leg_futur(df: pd.DataFrame) -> pd.DataFrame:
    """
    Convertit LEG_FUTUR -> format schedule interne.
    Toutes les colonnes originales sont conservees dans le DataFrame.
    """
    if "LEG_STATE" in df.columns:
        df = df[df["LEG_STATE"] == "NEW"].copy()
    else:
        df = df.copy()

    if "DAY_OF_ORIGIN" in df.columns:
        df["DAY_OF_ORIGIN"] = (
            df["DAY_OF_ORIGIN"]
            .astype(str)
            .str.strip()
            .str.replace(",", "", regex=False)
            .str.replace(" ", "", regex=False)
            .str.replace(r"\.0+$", "", regex=True)
            .str.extract(r"(\d{8})", expand=False)
            .fillna("")
        )

    carriers = df["FN_CARRIER"].apply(_normalize_flight_token)
    numbers  = df["FN_NUMBER"].apply(_normalize_flight_token)
    df["flight_id"] = [
        (f"{c}{n}" if c and n and any(ch.isdigit() for ch in f"{c}{n}")
         else (n if (not c and n and any(ch.isdigit() for ch in n)) else ""))
        for c, n in zip(carriers, numbers)
    ]
    df["origin"]        = df["DEP_AP_SCHED"]
    df["destination"]   = df["ARR_AP_SCHED"]
    df["aircraft_msn"]  = df["AC_REGISTRATION"]
    df["aircraft_type"] = df["AC_SUBTYPE"].astype(str)

    def _parse_hhmm(value) -> str:
        if pd.isna(value):
            return "0000"
        raw = str(value).strip()
        if not raw:
            return "0000"
        try:
            hhmm_int = int(float(raw))
            hhmm = f"{hhmm_int:04d}"[-4:]
        except (ValueError, TypeError):
            digits = "".join(ch for ch in raw if ch.isdigit())
            if not digits:
                return "0000"
            hhmm = digits[-4:].zfill(4)
        hh = int(hhmm[:2])
        mm = int(hhmm[2:4])
        if hh > 23 or mm > 59:
            return "0000"
        return hhmm

    def _parse_day(value) -> int:
        if pd.isna(value):
            return 0
        raw = str(value).strip()
        if not raw:
            return 0
        try:
            day_val = int(float(raw))
            return day_val % 100
        except (ValueError, TypeError):
            digits = "".join(ch for ch in raw if ch.isdigit())
            if not digits:
                return 0
            return int(digits[-2:])

    dep_t = df["DEP_TIME_SCHED"].apply(_parse_hhmm)
    arr_t = df["ARR_TIME_SCHED"].apply(_parse_hhmm)
    df["scheduled_departure"] = dep_t.str[:2] + ":" + dep_t.str[2:4]
    df["scheduled_arrival"]   = arr_t.str[:2] + arr_t.str[2:4]

    if "DEP_DAY_SCHED" in df.columns:
        dep_day = df["DEP_DAY_SCHED"].apply(_parse_day)
    elif "DAY_OF_ORIGIN" in df.columns:
        dep_day = df["DAY_OF_ORIGIN"].apply(_parse_day)
    else:
        dep_day = pd.Series([0] * len(df), index=df.index)

    if "ARR_DAY_SCHED" in df.columns:
        arr_day = df["ARR_DAY_SCHED"].apply(_parse_day)
    elif "DAY_OF_ORIGIN" in df.columns:
        arr_day = df["DAY_OF_ORIGIN"].apply(_parse_day)
    else:
        arr_day = pd.Series([0] * len(df), index=df.index)

    dep_min = dep_t.apply(lambda x: int(x[:2]) * 60 + int(x[2:4]))
    arr_min = arr_t.apply(lambda x: int(x[:2]) * 60 + int(x[2:4]))
    dur = (arr_day - dep_day) * 1440 + (arr_min - dep_min)
    dur.loc[dur < 0] += 30 * 1440
    df["flight_duration_min"] = dur

    if "DAY_OF_ORIGIN" in df.columns:
        d = df["DAY_OF_ORIGIN"].astype(str)
        df["flight_date"] = (
            d.str[:4] + "-" + d.str[4:6] + "-" + d.str[6:8]
        )
        bad_mask = df["flight_date"].str.contains(r"[^0-9\-]", na=True) | (df["flight_date"].str.len() != 10)
        df.loc[bad_mask, "flight_date"] = ""


    df["origin_city"] = df["origin"]
    df["dest_city"]   = df["destination"]
    df["leg_number"]  = 1
    df["legs_total"]  = 1

    df = df[df["flight_id"].astype(str).str.strip() != ""].copy()

    for _col in ["FN_NUMBER", "DEP_TIME_SCHED", "ARR_TIME_SCHED",
                 "DEP_DAY_SCHED", "ARR_DAY_SCHED", "LEG_SEQUENCE_NUMBER"]:
        if _col in df.columns:
            df[_col] = (
                df[_col]
                .astype(str)
                .str.replace(r"\.0+$", "", regex=True)
                .str.replace(",", "", regex=False)
            )

    return df.reset_index(drop=True)


_EXCEL_EPOCH = pd.Timestamp("1899-12-30")

def _clean_ac_msn(val) -> str:
    if val is None or (isinstance(val, float) and np.isnan(val)):
        return ""
    if isinstance(val, pd.Timestamp):
        serial = (val.normalize() - _EXCEL_EPOCH).days
        return str(serial)
    s = str(val).strip()
    if not s or s in {"nan", "NaT", "None", ""}:
        return ""
    if len(s) >= 10 and s[4] == "-" and s[7] == "-":
        try:
            t = pd.Timestamp(s)
            if t.year < 2000:
                serial = (t.normalize() - _EXCEL_EPOCH).days
                return str(serial)
            return s[:10]
        except Exception:
            pass
    if s.endswith(".0"):
        return s[:-2]
    return s


def _format_date_str(val) -> str:
    if val is None:
        return ""
    if isinstance(val, pd.Timestamp):
        return val.strftime("%Y-%m-%d") if pd.notna(val) else ""
    s = str(val).strip()
    if not s or s in {"nan", "NaT", "None"}:
        return ""
    if "T" in s:
        s = s.split("T")[0]
    return s[:10]


def _convert_doa_programe(df: pd.DataFrame) -> pd.DataFrame:
    """
    Convertit DOA_PROGRAME → format crew_pairing interne.

    Groupement par CREW_ID + DATE_LT (date locale opérationnelle).
    Tri des vols par DATE_LT + START_LT
    Clé de jointure avec le schedule : numéro de vol + date + ORIGINE + DESTINATION.
    """
    df = df.copy()

    # ── Remappage colonnes si nécessaire ──────────────────────
    if {"ACTIVITY_GROUP", "POS"}.issubset(df.columns):
        actg = df["ACTIVITY_GROUP"].astype(str).str.strip().str.upper()
        posv = df["POS"].astype(str).str.strip().str.upper()

        # Détection : POS contient FLT au lieu de ACTIVITY_GROUP
        colonnes_decalees = (not (actg == "FLT").any()) and (posv == "FLT").any()

        if colonnes_decalees:
            src = df.copy()  # snapshot sécurisé

            # Correction principale
            df["ACTIVITY_GROUP"] = src["POS"]

            # Ne pas casser les colonnes métier
            for col in [
                "ACTIVITY", "ORIGINE", "DESTINATION",
                "START_LT", "END_LT", "A_C"
            ]:
                if col in src.columns:
                    df[col] = src[col]

            # Gestion des dates/temps (corriger les manquants)
            if "START_UTC" in src.columns:
                df["START_UTC"] = src["START_UTC"].fillna(src.get("START_LT"))

            if "END_UTC" in src.columns:
                df["END_UTC"] = src["END_UTC"].fillna(src.get("END_LT"))

            # Colonnes optionnelles (sécurisées)
            for col in [
                "LAYOVER", "HOTEL", "BLOCK_HOURS",
                "BLC", "AUGMENTATION",
                "flight_sequence", "rest_sequence_min"
            ]:
                if col in src.columns:
                    df[col] = src[col]

    # Référence date
    _REF_DATE = pd.Timestamp("2000-01-01")

    def _epoch_minutes_lt(row) -> float:
        """
        Ordonne les vols par DATE_LT + START_LT
        """
        try:
            dt = pd.to_datetime(row["DATE_LT"], errors="coerce")
            if pd.isna(dt):
                return 0.0
            day_offset = (dt.normalize() - _REF_DATE).days * 1440

            # ── Heure locale : START_LT prioritaire ──────────
            t = row.get("START_LT")
            if t is None or (isinstance(t, float) and np.isnan(t)):
                return float(day_offset)
            if hasattr(t, "hour"):
                return day_offset + t.hour * 60 + t.minute
            parts = str(t).split(":")
            if len(parts) >= 2:
                try:
                    return day_offset + int(parts[0]) * 60 + int(parts[1])
                except ValueError:
                    pass
            return float(day_offset)
        except Exception:
            return 0.0

    # ── Filtrer les lignes de type FLT ────────────────────────
    df_flt = df[
        df["ACTIVITY_GROUP"].astype(str).str.strip().str.upper() == "FLT"
    ].copy()

    df_flt["_epoch"] = df_flt.apply(_epoch_minutes_lt, axis=1)
    df_flt = df_flt.sort_values(["CREW_ID", "DATE_LT", "_epoch"])

    # ── Groupement par CREW_ID + DATE_LT ─────────────────────
    crew_rows = []

    for (cid, duty_date), grp in df_flt.groupby(
        ["CREW_ID", "DATE_LT"], observed=True, sort=False
    ):
        grp = grp.sort_values("_epoch")

        # Collecter les vols avec leur origine et destination
        fids, origins, dests = [], [], []
        for _, r in grp.iterrows():
            tok = _normalize_flight_token(r["ACTIVITY"])
            if not tok:
                continue
            # Normaliser le numéro de vol (ex: "570" → "AT570")
            if tok.isdigit():
                tok = f"AT{tok}"
            elif not any(ch.isdigit() for ch in tok):
                continue  # Pas un vol (activité sol, etc.)

            fids.append(tok)
            origins.append(
                str(r["ORIGINE"]).strip().upper()
                if "ORIGINE" in grp.columns and pd.notna(r.get("ORIGINE"))
                else ""
            )
            dests.append(
                str(r["DESTINATION"]).strip().upper()
                if "DESTINATION" in grp.columns and pd.notna(r.get("DESTINATION"))
                else ""
            )

        if not fids:
            continue

        # ── Données complémentaires ───────────────────────────
        quals = (
            grp["AC_QUALS"].iloc[0]
            if "AC_QUALS" in grp.columns and not grp["AC_QUALS"].isna().all()
            else ""
        )
        rank     = grp["RANK_"].iloc[0]    if "RANK_" in grp.columns    else ""
        ac_codes = grp["A_C"].dropna().unique() if "A_C" in grp.columns else []
        msn      = _clean_ac_msn(ac_codes[0]) if len(ac_codes) > 0 else ""
        block    = grp["BLOCK_HOURS"].iloc[0] if "BLOCK_HOURS" in grp.columns else ""

        quals_str = str(quals).strip()
        ac_type   = quals_str if quals_str else str(msn)

        duty_start_str = _format_date_str(duty_date)

        # Normaliser l'identifiant équipage
        if pd.isna(cid):
            cid_str = "UNKNOWN"
        elif str(cid).replace(".", "", 1).isdigit():
            cid_str = str(int(float(cid)))
        else:
            cid_str = str(cid).strip()

        date_token = "".join(ch for ch in duty_start_str if ch.isdigit())[:8]
        if not date_token:
            date_token = str(duty_date).strip().replace(" ", "_")

        crew_rows.append({
            "crew_id":              f"CREW-{cid_str}-{date_token}",
            "CREW_ID_OPS":          cid_str,
            "flight_date":          duty_start_str,
            "aircraft_msn":         msn,
            "aircraft_type":        ac_type,
            "flight_sequence":      ";".join(fids),
            "n_flights":            len(fids),
            "RANK_":                rank,
            "AC_QUALS":             quals,
            "BLOCK_HOURS":          block,
            "ORIGINE":              origins[0] if origins else "",
            "DESTINATION":          dests[-1]  if dests   else "",
            # Séquences origine/destination par vol — utilisées pour la jointure 4-clés
            "ORIGINE_SEQUENCE":     ";".join(origins),
            "DESTINATION_SEQUENCE": ";".join(dests),
        })

    return pd.DataFrame(crew_rows)


# ─── Traitement interne du schedule ──────────────────────────

def _process_schedule(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    if "flight_id" in df.columns:
        df["flight_id"] = df["flight_id"].apply(_normalize_flight_token)
        df = df[df["flight_id"] != ""].copy()

    df["dep_min"] = df["scheduled_departure"].apply(hhmm_to_minutes)
    df["arr_min"] = df["scheduled_arrival"].apply(hhmm_to_minutes)

    mask_night = df["arr_min"] < df["dep_min"]
    df.loc[mask_night, "arr_min"] += 1440

    if "flight_duration_min" not in df.columns:
        df["flight_duration_min"] = df["arr_min"] - df["dep_min"]

    if "flight_date" in df.columns:
        dates = pd.to_datetime(df["flight_date"], errors="coerce")
        valid = dates.notna()
        if valid.any():
            j0 = dates.loc[valid].min()
            day_offset = (dates - j0).dt.days.fillna(0).astype(int)
            df["dep_min"] += day_offset * 1440
            df["arr_min"]  = df["dep_min"] + df["flight_duration_min"]

    if "flight_date" not in df.columns: df["flight_date"] = ""
    if "leg_number"  not in df.columns: df["leg_number"]  = 1
    if "legs_total"  not in df.columns: df["legs_total"]  = 1
    return df


def _recompute_crew_constraints(
    df_sched: pd.DataFrame, df_crew: pd.DataFrame
) -> pd.DataFrame:
    """
    Recalcule les séquences crew.

    Cle de jointure : numero de vol + date + origine + destination (4 cles).
    Date utilisee cote equipage : flight_date (issue de DATE_LT, heure locale).

    Note: rest_sequence_min est force a 0 pour ne pas ajouter de repos equipage.
    """
    if "flight_id" not in df_sched.columns:
        return df_crew
    if "crew_id" not in df_crew.columns or "flight_sequence" not in df_crew.columns:
        return df_crew

    # ── 1. Référentiel schedule normalisé ─────────────────────────────────────
    sched = df_sched[["flight_id"]].copy()
    sched["flight_id"]        = sched["flight_id"].astype(str).str.strip().str.upper()
    sched["flight_date_norm"] = (
        _to_date_str(df_sched["flight_date"])
        if "flight_date" in df_sched.columns
        else pd.Series([""] * len(df_sched), index=df_sched.index)
    )
    sched["origin"] = (
        df_sched["origin"].astype(str).str.strip().str.upper()
        if "origin" in df_sched.columns
        else ""
    )
    sched["destination"] = (
        df_sched["destination"].astype(str).str.strip().str.upper()
        if "destination" in df_sched.columns
        else ""
    )

    # ── 2. Exploser les séquences crew (1 ligne par vol) ──────────────────────
    rows = []
    for _, cr in df_crew.iterrows():
        seq_fids = [f.strip() for f in str(cr.get("flight_sequence", "")).split(";")]
        seq_orgs = [x.strip().upper() for x in str(cr.get("ORIGINE_SEQUENCE", "")).split(";")]
        seq_dsts = [x.strip().upper() for x in str(cr.get("DESTINATION_SEQUENCE", "")).split(";")]
        date_norm = _to_date_str(pd.Series([cr.get("flight_date", "")])).iloc[0]

        for i, fid_raw in enumerate(seq_fids):
            fid = str(fid_raw).strip().upper()
            if not fid:
                continue
            org = seq_orgs[i] if i < len(seq_orgs) else ""
            dst = seq_dsts[i] if i < len(seq_dsts) else ""
            rows.append({
                "crew_id":          cr["crew_id"],
                "flight_id":        fid,
                "flight_date_norm": date_norm,
                "origin":           org,
                "destination":      dst,
                "seq_pos":          i,
            })

    if not rows:
        return df_crew

    seq = pd.DataFrame(rows)

    # ── 3. Jointure 4-clés : vol + date + origine + destination ───────────────
    merged = seq.merge(
        sched[["flight_id", "flight_date_norm", "origin", "destination"]],
        on=["flight_id", "flight_date_norm", "origin", "destination"],
        how="left",
    )

    # ── 4. Agreger par crew_id ────────────────────────────────────────────────
    # Pas d'agrégation pour repos, simplement fusionner

    # ── 5. Fusionner avec df_crew ─────────────────────────────────────────────
    out = df_crew.copy()


    return out


def _group_crew_pairs(df_crew: pd.DataFrame) -> pd.DataFrame:
    """
    Fusionne les 2 lignes équipage (CC/CA) en 1 seule ligne par vol.

    Regroupement: flight_sequence + flight_date + ORIGINE + DESTINATION
    (avec fallbacks vers flight_id / origin / destination si disponibles).
    """
    if df_crew is None or df_crew.empty:
        return df_crew

    df = df_crew.copy()

    # Colonnes de regroupement avec fallbacks pour le format DOA
    _fallbacks = {
        "flight_sequence": "flight_id",
        "flight_date":     None,
        "ORIGINE":         "origin",
        "DESTINATION":     "destination",
    }
    group_keys = []
    for primary, fallback in _fallbacks.items():
        if primary in df.columns:
            group_keys.append(primary)
        elif fallback and fallback in df.columns:
            group_keys.append(fallback)

    if not group_keys:
        df["CC_ID"] = df.get("crew_id", "")
        df["CA_ID"] = ""
        df["crew_label"] = df["CC_ID"].astype(str).apply(lambda x: f"CC: {x}")
        return df

    cc_ranks = {"CMD", "CDB", "CC", "CPT", "CAPT", "PIC", "P1"}
    if "RANK_" in df.columns:
        df["_is_cc"] = df["RANK_"].apply(lambda r: str(r).strip().upper() in cc_ranks)
    else:
        df["_sort_num"] = pd.to_numeric(df["crew_id"], errors="coerce").fillna(0)
        df = df.sort_values(group_keys + ["_sort_num"])
        df["_is_cc"] = df.groupby(group_keys, sort=False, observed=True).cumcount() == 0

    rows = []
    for _, grp in df.groupby(group_keys, sort=False, observed=True):
        cc_grp = grp[grp["_is_cc"] == True]
        ca_grp = grp[grp["_is_cc"] == False]

        base  = grp.iloc[0].to_dict()
        cc_id = str(cc_grp["crew_id"].iloc[0]) if not cc_grp.empty else ""
        ca_id = str(ca_grp["crew_id"].iloc[0]) if not ca_grp.empty else ""

        base["CC_ID"]      = cc_id
        base["CA_ID"]      = ca_id
        base["crew_label"] = f"CC: {cc_id} | CA: {ca_id}" if ca_id else f"CC: {cc_id}"
        base["crew_id"]    = f"PAIR-{cc_id}-{ca_id or 'X'}"
        rows.append(base)

    result = pd.DataFrame(rows)
    drop_cols = [c for c in ["_is_cc", "_sort_num"] if c in result.columns]
    if drop_cols:
        result = result.drop(columns=drop_cols)
    return result.reset_index(drop=True)
# ══════════════════════════════════════════════════════════════
# Chargement avec détection automatique du format
# ══════════════════════════════════════════════════════════════

def load_uploaded_data(schedule_file, crew_file, ref_file=None):
    """
    Charge les fichiers uploadés dans Streamlit.
    Détecte automatiquement le format et traduit si nécessaire.
    """
    df_sched_raw = _read_file(schedule_file)
    df_crew_raw  = _read_file(crew_file)
    df_ref       = _read_file(ref_file) if ref_file else None

    if df_sched_raw is None or df_crew_raw is None:
        return None, None, None

    converted_sched = _is_ops_leg(df_sched_raw)
    converted_crew  = _is_ops_doa(df_crew_raw)

    df_sched = _convert_leg_futur(df_sched_raw) if converted_sched else df_sched_raw
    df_crew  = _convert_doa_programe(df_crew_raw) if converted_crew else df_crew_raw

    ok_s = _check_columns(df_sched, REQUIRED_SCHEDULE, schedule_file.name)
    ok_c = _check_columns(df_crew,  REQUIRED_CREW,     crew_file.name)
    if not ok_s or not ok_c:
        return None, None, None

    if df_ref is not None:
        ref_cols_norm = {str(c).strip().lower() for c in df_ref.columns}
        # Evite le message d'erreur "param_type, value" quand un fichier turnaround est chargé ici.
        if REQUIRED_REF.issubset(ref_cols_norm):
            df_ref = df_ref.copy()
            df_ref.columns = [str(c).strip().lower() for c in df_ref.columns]
        elif {"airport", "aircraft_type", "min_turnaround_min"}.issubset(ref_cols_norm):
            st.info(
                f"Le fichier **{ref_file.name}** ressemble à un fichier turnaround. "
                "Les paramètres de référence par défaut seront utilisés."
            )
            df_ref = None
        else:
            _check_columns(df_ref, REQUIRED_REF, ref_file.name)

    df_sched = _process_schedule(df_sched)
    if "flight_sequence" in df_crew.columns:
        df_crew = df_crew.copy()
        df_crew["flight_sequence"] = df_crew["flight_sequence"].fillna("").apply(_normalize_flight_sequence)
        df_crew = df_crew[df_crew["flight_sequence"] != ""].copy()

    if "flight_sequence" in df_crew.columns and "rest_sequence_min" not in df_crew.columns:
        df_crew = _recompute_crew_constraints(df_sched, df_crew)
    elif converted_crew:
        df_crew = _recompute_crew_constraints(df_sched, df_crew)

    df_crew = _group_crew_pairs(df_crew)

    return df_sched, df_crew, df_ref


# ─── Chargement du fichier turnaround CSV ────────────────────

def load_turnaround_table(uploaded_file) -> dict:
    """
    Charge le fichier CSV/Excel turnaround uploadé via Streamlit.

    Format attendu : airport, aircraft_type, min_turnaround_min
    Retourne un dict avec clés (airport, aircraft_type) → minutes.
    La ligne (DEFAULT, DEFAULT) sert de valeur par défaut globale.

    Hiérarchie de lookup (dans _resolve_min_turnaround) :
      1. (airport, aircraft_type)   — correspondance exacte

    """
    if uploaded_file is None:
        return {}

    df = _read_file(uploaded_file)
    if df is None or df.empty:
        st.warning("Fichier turnaround vide ou illisible — valeurs par défaut utilisées.")
        return {}

    required = {"airport", "aircraft_type", "min_turnaround_min"}
    raw_cols = [str(c).strip() for c in df.columns]
    raw_to_norm = {c: c.lower() for c in raw_cols}

    alias_map = {
        "airport": {
            "airport", "aeroport", "apt", "station", "origin", "dep_ap_sched",
        },
        "aircraft_type": {
            "aircraft_type", "ac_type", "aircraft", "type_avion", "fleet", "ac_subtype",
        },
        "min_turnaround_min": {
            "min_turnaround_min", "min_turnaround", "turnaround_min", "tat_min",
        },
    }

    rename_dict = {}
    taken_targets = set()
    for raw, norm in raw_to_norm.items():
        for target, aliases in alias_map.items():
            if norm in aliases and target not in taken_targets:
                rename_dict[raw] = target
                taken_targets.add(target)
                break

    df = df.rename(columns=rename_dict)
    df.columns = [str(c).strip().lower() for c in df.columns]

    missing = required - set(df.columns)
    if missing:
        st.error(
            "Le fichier turnaround doit contenir les colonnes : "
            "`airport, aircraft_type, min_turnaround_min`\n\n"
            f"Colonnes manquantes : `{', '.join(sorted(missing))}`\n\n"
            f"Colonnes trouvées : `{', '.join([str(c) for c in raw_cols])}`"
        )
        return {}

    table = {}
    for _, row in df.iterrows():
        airport = str(row["airport"]).strip().upper()
        ac_type = str(row["aircraft_type"]).strip().upper()
        try:
            minutes = float(str(row["min_turnaround_min"]).replace(",", "."))
        except (ValueError, TypeError):
            continue
        table[(airport, ac_type)] = minutes

    return table


# ─── Extraction paramètres de référence ──────────────────────

def build_ref_dicts(df_ref, turnaround_table=None):
    """
    Retourne les paramètres de simulation.

    Si turnaround_table est fourni (dict issu du CSV uploadé),
    il est retourné tel quel en 6ème position.
    Sinon, un fallback DEFAULT est utilisé.

    Retourne: (min_turnaround, gamma_shape, gamma_scale,
               markov_matrix, markov_multipliers, turnaround_table)
    """
    min_turnaround = {
        "DEFAULT": 45.0,
    }
    gamma_shape        = 2.5
    gamma_scale        = 15.0
    markov_matrix      = np.array([
        [0.65, 0.28, 0.07],
        [0.25, 0.52, 0.23],
        [0.08, 0.28, 0.64],
    ])
    markov_multipliers = [1.0, 1.45, 2.30]

    if turnaround_table is None:
        turnaround_table = {}

    if df_ref is None or "param_type" not in df_ref.columns:
        return min_turnaround, gamma_shape, gamma_scale, \
               markov_matrix, markov_multipliers, turnaround_table

    states = {"Normal": 0, "Alerte": 1, "Bloqué": 2}

    for _, row in df_ref.iterrows():
        pt  = str(row.get("param_type", "")).strip()
        at  = str(row.get("aircraft_type", "")).strip()
        try:
            val = float(row.get("value", 0))
        except (ValueError, TypeError):
            continue

        if pt == "min_turnaround_min":
            pass
        elif pt == "gamma_shape":
            gamma_shape = val
        elif pt == "gamma_scale":
            gamma_scale = val
        elif pt == "markov_transition":
            try:
                src, dst = at.split("→")
                i = states[src.strip()]
                j = states[dst.strip()]
                markov_matrix[i, j] = val
            except Exception:
                pass
        elif pt == "markov_turnaround_multiplier_normal":
            markov_multipliers[0] = val
        elif pt == "markov_turnaround_multiplier_alerte":
            markov_multipliers[1] = val
        elif pt == "markov_turnaround_multiplier_bloque":
            markov_multipliers[2] = val

    return min_turnaround, gamma_shape, gamma_scale, \
           markov_matrix, markov_multipliers, turnaround_table


if __name__ == "__main__":
    mt, gs, gsc, mm, mp, tt = build_ref_dicts(None)
    print("data_loader: defaults OK")
    print(f"Turnaround DEFAULT={mt.get('DEFAULT', 45.0)}")
